[未知类型(tool_articles): {"type": "tool_articles", "tool_articles": [{}]}]',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZCTGV1H8CZ2KH8TRKR4','药物相关','咨询用药','{"回答标签": ["建议就医", "提供就医指引", "推荐科普内容"], "场景标签": ["用药咨询", "血压监测"], "患者标签": ["血压达标", "脉搏正常", "头晕"], "患者发言标签": ["咨询本人", "疑问语气"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:51:55.693675+08','场景描述结合患者提供的血压、心率数值，按规则判断血压达标、脉搏正常，同时结合患者头晕症状和用药咨询需求整理；患者提问将患者的血压、心率、症状及用药疑问整合为清晰完整的问题；回复案例对其中的具体日期进行脱敏处理，其余内容保留原文结构和信息。',0.9500,'74db78a69a9449c2674a0a100cd62848','success',NULL,'20260210153948'),
	 ('01KH37W08AGT9V6B7CXR47RA29','患者咨询药物的服用剂量，询问是否可以吃一片，并提供了药盒图片','你好，我想问一下这个药怎么吃，是吃一片吗？','理解你想了解药物的具体服用方法，不过用药剂量涉及个体差异，需要根据你的具体健康状况、血压水平、合并疾病等综合评估。每个人的用药方案都是医生根据具体情况制定的，不能一概而论。建议你仔细查看药品说明书上的用法用量说明，或者咨询开具处方的医生或专业药师，他们会根据你的具体情况给出准确的用药指导。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZDB62FBNB2K3H4W51SA','药物相关','用药剂量咨询','{"回答标签": ["未直接回答患者问题"], "场景标签": ["用药咨询"], "患者标签": [], "补充标签": [], "患者发言标签": ["咨询本人", "疑问语气"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:53:13.818799+08','场景描述、患者提问均基于患者当前发言内容整理，保留原意并明确咨询需求；回复案例直接使用提供的内容，未做修改；场景及子场景根据患者咨询用药剂量的内容判定',0.9500,'f47de1bbe1bd84ff15392cacf4c5df78','success',NULL,'20260210153948'),
	 ('01KH0YT1MARN1Y1SCW68GSS9JQ','50岁糖尿病患者，规律服用[二甲双胍]，睡眠良好，7天血压趋势下降，本次自测血压129/70mmHg，达标，脉搏72次/分，正常，告知医护人员相关数据。','记录我今天的血压：高压129，低压70，脉搏72','你能主动监测并告诉我血压情况，这个习惯非常棒！已经帮你记录了今天的血压数据：129/70 mmHg，脉搏72次/分。从单次测量结果来看，你的血压处于正常范围，脉搏也在正常区间。不过单次血压测量结果会受到多种因素影响，建议你继续坚持规律监测血压，尤其是早晨起床后和晚上睡前这两个时段，这样能更全面地了解自己的血压波动情况。为了让你更直观地查看近期血压变化趋势，你可以通过血压趋势图工具来了解血压的整体情况。考虑到你可能想了解更多关于血压管理的知识，这里有一些专业可靠的健康科普文章推荐给你，帮助你深入了解相关健康知识。另外，如果你需要了解医生近一个月的门诊排班信息，以便安排就诊时间和预约，可以查看门诊排班详情。需要注意的是，该工具只能查看门诊排班，预约需要通过医院官方渠道进行。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYDMP41STSKSTBM2ZX1F','记录血压','自测血压脉搏记录','{"回答标签": ["正向引导", "健康科普推荐", "就诊指引"], "场景标签": ["血压记录", "脉搏记录"], "患者标签": ["50岁", "糖尿病", "规律服药", "血压达标", "脉搏正常"], "补充标签": ["血压趋势下降"], "患者发言标签": ["陈述事实", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-09 18:22:58.698184+08',NULL,'场景描述结合患者年龄、疾病、用药、血压趋势等历史信息，以及本次自测的血压、脉搏数据，按规则判定血压达标、脉搏正常；患者提问将患者的陈述改写为明确的记录请求；回复案例仅按要求脱敏敏感信息，未改动其他内容；场景根据患者记录血压的行为判定为记录血压场景。',1.0000,'9cadae201ede5348f254bab25ce572d5','success','null',NULL);
INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH600GMQKGFAFTQ4D5WJ2ZGH','45岁高脂血症患者，规律服用[阿托伐他汀]，有少吃盐、运动的习惯，14天血压趋势无突出，本次在[日期]上午徒步回来后测得血压131/81mmHg，血压达标，向医生告知该血压测量结果。','记录[日期]上午徒步回来后测得的血压131/81mmHg','你能主动监测并告知血压情况，这个习惯很不错。从你提供的血压数据来看，此次测量的血压值为131/81mmHg，在正常血压范围内。不过单次的血压测量可能会受到多种因素影响，比如测量时的状态、测量仪器的准确性等，建议你可以在不同时间多测量几次，这样能更全面地了解自己的血压情况。
另外，因为你有高脂血症的病史，血脂异常可能会影响血管的状态，进而对血压产生一定影响，所以除了监测血压，也别忘了关注血脂的控制情况，遵循医生的建议进行治疗和生活方式的调整。
你可以通过阅读健康科普文章了解更多关于高血压和高脂血症管理的专业知识：

articleId=2177, articleTitle=你今天测血压了吗？动动手，测量并记录，给自己的健康上一道保险吧。, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/MTc1NDYyMTQ2MDMxNGRjYWZlNmVhLTQ2NWUtNGE0Mi1hZGM2.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=LXE%2BKRi391yMt0LSKS0CajlgHjI%3D&response-content-disposition=inline&image_process=resize,l_300
