scheduleStartDay=[日期], scheduleEndDay=[日期]',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ7Y7Y470ZQTFQ7ZMERD','记录血压','血压情况反馈','{"回答标签": ["带健康科普文章", "带行动建议", "带血压点评"], "场景标签": ["血压记录", "血压反馈"], "患者标签": ["50岁", "糖尿病", "规律服药", "血压轻度偏高"], "补充标签": [], "患者发言标签": ["陈述病情", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:33:06.330588+08','场景描述结合患者年龄、基础病、用药情况、血压趋势及本次血压信息整理；患者提问根据患者当前发言改写为清晰的表述；回复案例对其中具体日期进行脱敏处理；依据患者发言内容及上下文信息确定场景及子场景。',0.9500,'72470f4b3172f617443d320771c84efb','success',NULL,'20260211172011'),
	 ('01KH37W03C16DFSZ1D9HDKQZK5','患者向医生发送消息，请求帮忙查看复诊报告','麻烦徐医生帮忙看一下这份复诊报告可以吗？','我注意到你提到了复诊报告，但目前我没有看到具体的报告内容。为了能帮你分析报告中的关键指标和健康状况，建议你将报告的文字内容或清晰图片提供给我，我会帮你解读其中与高血压管理相关的重要信息。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ6QFQ4BB67BKHNTYJYD','诊疗相关','复诊报告解读请求','{"回答标签": ["引导补充信息"], "场景标签": ["复诊报告解读"], "患者标签": [], "补充标签": [], "患者发言标签": ["语气礼貌", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:39:59.492269+08','场景描述根据患者请求查看复诊报告的行为提炼；患者提问将原发言改写为完整清晰的请求句式；回复案例按原文保留，未涉及敏感信息无需脱敏；场景判断为诊疗相关下的报告解读请求',0.9500,'890d9516621eef4d859e867ef099b235','success',NULL,'20260210153948'),
	 ('01KH37W03FN16NPR801S0PTDDP','患者称医生开具了冠心苏合，但无法获取该药物，咨询是否可以用心可舒丸替代。','医生让我吃冠心苏合，但我没有这个药，能不能吃心可舒丸来代替呢？','心可舒丸和冠心苏合虽然都常用于心血管疾病辅助治疗，但成分和功效特点有所不同，属于不同类型的中成药。目前这两种药物用于心血管疾病治疗的循证医学证据都相对有限，不建议自行替换或调整药物方案。药物选择需要考虑个人具体病情、症状特点、体质等多方面因素，建议你及时与开具处方的医生沟通，说明目前的情况，由医生根据你的具体健康状况评估是否适合调整用药方案，切勿自行换药。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ6WZ8648B14T8RS1F5K','药物相关','咨询调整用药','{"回答标签": ["专业建议", "引导就医沟通"], "场景标签": ["药物替换咨询"], "患者标签": ["心血管疾病患者"], "补充标签": [], "患者发言标签": ["咨询本人用药", "语气平实"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:40:08.611881+08','场景描述、患者提问均基于患者原始发言改写，保留原意并明确核心诉求；回复案例直接使用提供的内容，未涉及敏感信息无需脱敏；场景和子场景根据患者咨询药物替换的诉求判定。',0.9500,'0cc51ada6c6ea212329f544aaf284e80','success',NULL,'20260210153948');
