content=

scheduleStartDay=[日期], scheduleEndDay=[日期]',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYDRP4G21WZ10MEH840A','记录血压','记录血压及脉搏数据','{"回答标签": ["语气友好", "有推荐文章", "提及门诊排班"], "场景标签": ["血压记录", "脉搏记录"], "患者标签": ["55岁", "脑梗", "视力模糊", "血压夜间高", "不规律服药", "血压达标", "脉搏正常"], "补充标签": [], "患者发言标签": ["陈述事实", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-09 18:23:18.124248+08',NULL,'场景描述结合患者年龄、疾病、症状、血压趋势、服药情况及今日血压脉搏数据生成；患者提问将患者的陈述改写为明确的记录请求；回复案例对其中的具体日期进行脱敏处理；无回复规则内容；结合患者发言及上下文信息确定场景及子场景；标签根据场景、患者情况、发言及回复内容提取。',0.9500,'9547baedbb3b6212527558e5088e99c6','success','null',NULL),
	 ('01KH37W038X8NYQGGF5ACF0DCH','患者想要预约[医生]进行造影检查，向相关人员发起咨询','您好！我想约龙医生，做造影，该怎么操作？','你可以先查看[医生]近一个月的门诊排班信息，了解他的出诊时间安排。[未知类型(tool_doctor_schedule): {"type": "tool_doctor_schedule", "tool_doctor_schedule": {"start_day": "[日期]", "end_day": "[日期]"}}]需要说明的是，我无法直接帮你预约挂号，建议你在确认医生出诊时间后，通过[医院]官方渠道（如官网、公众号或官方电话）进行预约。另外，冠状动脉造影属于有创检查，需要医生面诊评估后开具检查单，你到院就诊时可以和医生详细沟通检查相关事宜。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ6HJKX46692FVST0SQM','院内资源/政策咨询','预约挂号及检查咨询','{"回答标签": ["引导自主预约", "告知检查要求"], "场景标签": ["预约检查", "医生预约"], "患者标签": ["有造影检查需求"], "补充标签": [], "患者发言标签": ["语气礼貌", "咨询本人需求"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:40:18.013137+08','场景描述根据患者预约医生做造影的需求结合脱敏规则生成；患者提问结合回复案例将患者的诉求补充为完整问题；回复案例对其中的医生姓名、具体日期、医院相关信息按脱敏规则替换为占位符；场景和子场景根据患者预约挂号及检查的诉求判定',0.9500,'fe43017bb0b9a9e6048e97da0c13dd71','success',NULL,'20260210153948'),
	 ('01KH37W044XK71A19YYEAZZ165','患者此前咨询挂号相关问题，得到回复后表示将再观察两天','我再观察两天','观察期间要特别注意血压变化情况，建议每天早晚各测量一次血压并做好记录。如果出现血压持续升高超过140/90mmHg，或者伴随头痛、头晕、胸闷等不适症状，要及时就医咨询。另外，这两天也要继续保持规律作息和低盐饮食，避免情绪波动和过度劳累。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ7F2K74G09Y6SRBXM5E','其它场景','后续观察告知','{"回答标签": [], "场景标签": ["后续观察"], "患者标签": ["高血压慢病"], "补充标签": [], "患者发言标签": ["告知类发言"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:41:04.286301+08','场景描述结合聊天历史中患者的挂号咨询及当前发言整理；患者提问保留患者原意；回复案例按原文保留，未涉及敏感信息无需脱敏',0.9000,'1236c329345b5d9d72c1c106c51049b5','success',NULL,'20260210153948'),
	 ('01KH37W0449R52N349EYBDT4XX','患者向医生数字分身咨询特药开方时间相关问题','你好，能不能查询我什么时候可以开特药？谢谢🙏','作为医生的数字分身，当前可以为你提供高血压慢病健康管理及科学指导，你咨询的此类问题暂无法回复，建议你通过医院的官方渠道（如官网、公众号或官方电话）直接咨询。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ7GZPKAPY7RS26NAJC0','院内资源/政策咨询','特药开方时间查询','{"回答标签": ["明确告知无法回复", "引导官方渠道咨询"], "场景标签": ["特药咨询", "开方时间查询"], "患者标签": [], "补充标签": [], "患者发言标签": ["语气礼貌", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:41:05.662696+08','场景描述根据患者咨询特药开方时间的内容提取；患者提问将原发言改写为完整清晰的问题，保留原意；回复案例按要求保留原内容未做修改；场景根据患者咨询院内特药相关事宜判定为院内资源/政策咨询，子场景细化为特药开方时间查询',1.0000,'ccbc041cb38883d71319d3e726d0699b','success',NULL,'20260210153948'),
	 ('01KH37W045XVGED87HM6976FC1','高血压患者此前咨询服药期间大便困难能否吃麻仁软胶囊，得到不建议自行服用的回复后，告知药物购买地点','告知助理麻仁软胶囊是在[药店]买的','你的问题似乎与高血压慢病健康管理无关。如果你有关于血压监测、用药管理、饮食运动等高血压相关的健康问题，我可以为你提供专业的咨询和建议。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ7JDBWJ3NE7JTJNV89X','其它场景','告知药物购买地点','{"回答标签": [], "场景标签": ["告知购买地点"], "患者标签": ["高血压患者", "服药期间大便困难"], "补充标签": [], "患者发言标签": ["陈述事实"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:41:12.842516+08','场景描述结合聊天历史中患者的咨询及当前发言内容，脱敏药店名称；患者提问改写自当前患者发言，明确告知内容；回复案例保留原内容；场景根据患者当前发言判定为其它场景，子场景明确为告知药物购买地点',0.9000,'a40959995a96806a093ac495a322060f','success',NULL,'20260210153948'),
	 ('01KH37W048S7K9JRT7K9PS17WS','高血压患者此前咨询地平片能否一次吃两片，还告知今早出现头晕但血压不高，在得到助理的解答建议后向助理表达感谢。',NULL,'不客气。如果有高血压相关的健康问题，比如血压监测、饮食调理、运动建议等，都可以随时告诉我，我会尽力为你提供帮助。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ7N3375DX2D0D5JNSW2','其它场景','致谢场景','{"回答标签": ["语气友好"], "场景标签": ["致谢"], "患者标签": ["高血压", "头晕"], "补充标签": [], "患者发言标签": ["语气礼貌", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:41:48.853664+08','场景描述结合聊天历史中患者的咨询内容和当前的致谢发言整理，回复案例使用给定内容，当前患者发言为致谢无提问内容故未改写提问，无回复规则。',1.0000,'0657e519ff990a7c6541f9ad37eb71b7','success',NULL,'20260210153948');
INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH0YTMZ0YF6318DY1KC23BHA','55岁脑梗患者，存在肢体麻木症状，有不规律服用[拜阿斯匹灵]的情况，今日自测血压高压190、低压112，属于重度偏高（需预警，尽快回院），脉搏72次/分，为正常脉搏。','我今天的血压高压190，低压112，脉搏72，请帮我记录','你能主动监测并告诉我血压情况，这个习惯非常棒！已经帮你记录下今天的血压数据。
你目前的血压值（190/112 mmHg）明显高于正常范围，这种情况需要引起高度重视。血压显著升高可能会增加心脑血管事件的风险，建议你尽快前往医院就诊，让医生评估当前状况并给予专业指导。
考虑到你需要安排就诊，这里可以帮你查看医生近一个月的门诊排班信息，方便你了解就诊时间安排。

scheduleStartDay=[日期], scheduleEndDay=[日期]
content=

同时，关于高血压急症的识别与处理，有一些专业可靠的健康科普文章可以帮助你深入了解相关知识，建议你点击查看。

