scheduleStartDay=[日期], scheduleEndDay=[日期]',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYFHXG4N73PAC6B75RC8','记录血压','记录当日血压及脉搏','{"回答标签": ["语气友好", "有推荐文章", "带排班信息"], "场景标签": ["血压记录", "脉搏记录"], "患者标签": ["60岁", "高血压", "冠心病", "有胸痛症状", "血压达标", "脉搏正常", "近期血压趋势上升"], "患者发言标签": ["陈述告知", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-09 18:25:51.247292+08',NULL,'场景描述结合患者年龄、疾病史、症状、血压趋势及本次血压脉搏信息整理；患者提问根据当前发言明确记录需求；回复案例对其中具体日期做脱敏处理，其余保留原文内容；场景及子场景根据患者记录血压的需求判定',0.9500,'95c0a5842a6dc6c236b53cbd8afcf0c5','success','null',NULL),
	 ('01KH37W047TKFQBMGKR9G36ZCZ','患者今日晨起出现头晕症状，平日无此症状，咨询地平片能否一次吃两片。','我今天早晨出现头晕症状，平时不晕，请问地平片一次吃两片可以吗？','调整降压药物剂量需要根据个人血压水平、身体状况和医生评估来确定，不能自行决定增加剂量。地平类药物属于处方药，随意增加剂量可能会导致血压过低、心率加快等不良反应，甚至影响心脏功能。头晕可能与血压波动有关，也可能是其他健康问题的信号，需要先明确原因再调整用药。建议你先测量血压并记录数值，然后联系医生说明情况，由医生根据你的具体状况判断是否需要调整药物剂量或方案。千万不要自行增加药量，以免带来健康风险。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ7KX9MWJA2B5S6NZEVK','药物相关','用药剂量咨询','{"回答标签": ["专业严谨", "直接解答风险", "给出就医建议"], "场景标签": ["用药咨询"], "患者标签": ["头晕症状"], "补充标签": [], "患者发言标签": ["咨询本人", "语气礼貌"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:41:16.477847+08','场景描述根据患者当前发言提取症状及咨询需求；患者提问将原发言表述模糊处梳理清晰，明确症状与用药疑问；回复案例按原文保留，未涉及敏感信息无需脱敏；场景及子场景根据患者咨询用药剂量的需求判定。',0.9500,'6ae374149116fc144f32f51063044d4e','success',NULL,'20260210153948'),
	 ('01KH37W049VKRKBHQXH22ZQS63','患者向医生咨询是否有拜新同和络活喜两种药物','赵大夫，请问现在有拜新同和络活喜吗？','作为医生的数字分身，当前可以为你提供高血压慢病健康管理及科学指导，你咨询的此类问题暂无法回复，建议你通过[医院]的官方渠道（如官网、公众号或官方电话）直接咨询。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ7QHEWS6FN048W2RHBT','院内资源/政策咨询','咨询院内是否有某个药','{"回答标签": ["未直接回答患者问题"], "场景标签": ["药品库存咨询"], "患者标签": [], "补充标签": [], "患者发言标签": ["咨询本人相关", "语气礼貌"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:41:31.120156+08','场景描述根据患者咨询药物库存的内容提取；患者提问保留原句仅补充标点；回复案例按脱敏规则将具体医院替换为[医院]占位符；场景和子场景根据患者咨询院内药品库存的内容判定',1.0000,'41dc5826a9e43048ba7afb816ac2fd2f','success',NULL,'20260210153948');
INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH37W04ERN6C6P4J1HQ0PYWJ','患者计划[日期]前往[医院]拿药，但未挂上号，向医护人员寻求解决办法','你好，我明天要去拿药，但是没挂上号，该怎么办？','加号通常需要医生根据当日门诊工作量和实际情况决定，建议你明天早些到[医院]诊室，在医生出诊时礼貌询问是否有加号可能。另外，也可以关注[医院]官方渠道的号源更新，有时会有临时退号的情况。如果这次确实无法加号，不要着急，可以咨询导诊台或门诊服务中心，了解后续的挂号安排和就医建议。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ7W018320JM142SDZ5Y','院内资源/政策咨询','挂号/加号咨询','{"回答标签": ["给出解决建议"], "场景标签": ["挂号咨询", "加号咨询"], "患者标签": [], "补充标签": [], "患者发言标签": ["语气礼貌", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:41:46.082185+08','场景描述结合患者发言信息，对敏感信息进行脱敏处理；患者提问将原发言补充完整为清晰的问题；回复案例对其中的具体医院进行脱敏替换为[医院]，保留原回复内容',1.0000,'42e7b49457b08d9b639d5ca4ac9c6f11','success',NULL,'20260210153948'),
	 ('01KH0YWJCMZCH1GRDJAZNF6AM4','35岁高血压患者，规律服用[苯磺酸氨氯地平片]，有夜尿增多症状，14天血压趋势晨间高，本次自测血压129/70mmHg，脉搏72次/分钟，血压达标，脉搏正常，告知医护人员本次监测数据。','我今天的血压高压129，低压70，脉搏72，请记录','你能主动监测并记录血压，这个习惯非常好，我已经帮你保存了今天的血压记录。从数据来看，你的血压值为129/70mmHg，脉搏72次/分钟，目前这个血压状态处于正常范围，脉搏也在理想区间内，整体情况比较稳定。为了更全面地了解你的血压控制情况，建议你继续坚持规律监测血压并记录，随着数据积累，我们可以更好地分析血压变化趋势。你可以通过查看医生近一个月的门诊排班信息，提前规划复诊安排，方便及时与医生沟通血压管理情况。scheduleStartDay=[日期], scheduleEndDay=[日期]content=同时，你也可以阅读一些专业可靠的健康科普文章，帮助自己深入了解高血压相关的健康知识，更好地进行自我健康管理。articleId=512, articleTitle=高压145mmHg，低压60mmHg，我到底是高血压？还是低血压？, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/ae4068ae4314789aa8d9e5b0820d1750.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=HX3xzUt0gqdyouXJEcFJqt%2FuIHg%3D&response-content-disposition=inline&image_process=resize,l_300articleId=870, articleTitle=血压高一点儿，但又不到高血压的标准？, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/2efecc5c6504a21351c22745d88f3310.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=VjdsxhknfzM0V18P5swJdUwyf7M%3D&response-content-disposition=inline&image_process=resize,l_300articleId=891, articleTitle=高压高，低压正常，是高血压吗？, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/4ddbbf52fad8a79dc352fe2fe2c2337a.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=VOICcaoruBOV51M9v3E9Vhe3S80%3D&response-content-disposition=inline&image_process=resize,l_300',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYEFB0K1NHTTTDEAJT2Q','记录血压','血压脉搏数据记录','{"回答标签": ["语气友好", "有推荐文章", "提及复诊"], "场景标签": ["血压记录", "脉搏记录"], "患者标签": ["35岁", "高血压", "夜尿增多", "规律服药", "血压达标", "脉搏正常"], "补充标签": [], "患者发言标签": ["陈述事实", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-09 18:24:21.396526+08',NULL,'场景描述结合患者年龄、病史、用药情况、症状、血压趋势及本次监测数据生成；患者提问根据本次发言明确记录需求改写；回复案例对具体日期进行脱敏处理；根据患者明确提供血压脉搏数据并要求记录的内容确定场景及子场景',0.9500,'f682e1673a2e287aeb6bcd32907aa096','success','null',NULL),
	 ('01KH0YXW884GC6B70HC1V2G5D5','70岁的高血压、高脂血、冠心病患者，有头昏头晕症状，存在14天血压趋势上升、不规律服药的情况，本次告知今日血压129/70mmHg，脉搏72次/分，血压达标，脉搏正常，该患者属于高血压、高脂血、冠心病且有头昏头晕症状需预警，尽快回院。','请帮我记录今天的血压：高压129，低压70，脉搏72','你能主动监测并记录血压，这个习惯非常好，已经帮你保存了今天的血压记录。今天的血压129/70mmHg，属于正常范围，脉搏72次/分也在正常区间，整体情况不错。不过单次血压测量结果会受多种因素影响，建议你继续坚持定期监测血压，尤其是在每天的固定时间（如早晨起床后、晚上睡前）测量，这样能更全面地了解自己的血压变化趋势。
为了让你更直观地了解后续血压变化情况，可以通过查看医生门诊排班信息，提前规划复诊安排，及时与医生沟通血压控制情况。

