articleId=891, articleTitle=高压高，低压正常，是高血压吗？, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/4ddbbf52fad8a79dc352fe2fe2c2337a.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=VOICcaoruBOV51M9v3E9Vhe3S80%3D&response-content-disposition=inline&image_process=resize,l_300',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYFQ0TGSWSRAB3MMZAVQ','记录血压','日常血压脉搏记录','{"回答标签": ["友好引导", "带推荐文章"], "场景标签": ["血压记录", "脉搏记录"], "患者标签": ["64岁", "高脂血症", "糖尿病", "高血压", "肌肉无力", "规律服药", "血压趋势下降", "血压达标", "脉搏正常"], "补充标签": ["需预警", "尽快回院"], "患者发言标签": ["陈述告知", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-09 18:26:02.886207+08',NULL,'场景描述结合患者年龄、基础疾病、用药情况、既往血压趋势、症状及本次上报的血压脉搏数据，同时根据回复参考标签补充预警提示；患者提问将患者的陈述转化为明确的记录请求；回复案例对其中的具体日期进行脱敏处理；根据患者当前发言内容判断场景为记录血压。',0.9500,'1e0d4c2362f61b036da9daaadacd4251','success','null',NULL),
	 ('01KH37W05H2MR0KGHSTG3Y5KMH','患者发送了一个活动链接，询问该链接是什么信息以及如何填写，此前患者曾咨询取礼物的问题，均不属于高血压慢病相关健康服务范围。','这个活动链接是什么信息？该怎么填写？','我是医生的数字分身，可以智能响应您的健康需求。您提供的内容看起来是一个活动链接，这不属于我的服务范围。有高血压慢病相关的健康问题可以随时沟通，我会为您提供专业的健康指导。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ9QGMS5ZHE0DMHJ6QQA','非医学类问题','咨询非健康服务类的活动链接相关问题','{"回答标签": ["明确告知服务范围"], "场景标签": ["非医学问题", "活动链接咨询"], "患者标签": [], "补充标签": [], "患者发言标签": ["咨询非本人健康问题"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:44:38.717414+08','根据患者当前发言及历史聊天记录，脱敏后还原患者的问题场景，将患者的口语化表述改写为清晰的提问，回复案例直接使用给定内容并确认符合脱敏规则。',1.0000,'7ba555600c0ae6807d7a1f8d01c9fc43','success',NULL,'20260210153948');
INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH37W04T52548N5274ST7V14','患者药物服用完毕，咨询购药开方的渠道','药吃完了去哪里开呀？','药物需要医生根据你的具体情况开具处方，建议你通过[医院]官方渠道（如官网、公众号或官方电话）预约就诊，医生会根据你的血压控制情况和身体状态评估后开具合适的药物。就诊时记得携带之前的用药记录和检查报告，这样医生能更全面地了解你的情况。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ851HN1THGSDW21T9P9','药物相关','开处方','{"回答标签": ["给出明确指引"], "场景标签": ["开方咨询"], "患者标签": ["药物已服完"], "补充标签": [], "患者发言标签": ["咨询本人需求", "语气平和"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:42:51.030474+08','场景描述根据患者咨询开方渠道的需求提炼；患者提问保留原句；回复案例对其中的具体医院信息进行脱敏处理，替换为[医院]占位符',0.9500,'281d83746142e4a0b0522f928931e3ab','success',NULL,'20260210153948'),
	 ('01KH37W04Z9VNA752DWFNE3ZH2','患者咨询血压波动与食用海鲜之间是否存在关联','血压波动跟吃海鲜有没有关系？','注意到你观察到食用海鲜后血压有升高的情况，这种细致的自我观察对血压管理很有帮助。海鲜本身是优质蛋白质的良好来源，但不同种类的海鲜在钠含量上有差异，比如加工过的海鲜制品（如咸鱼、虾米、鱿鱼干等）通常含盐量较高，过量摄入可能导致短期内血压波动。另外，烹饪方式也会影响，比如红烧、酱爆等做法往往会添加较多盐分和酱油，这也可能是血压升高的一个因素。每个人对饮食中盐分的敏感程度不同，既然你注意到这个关联，以后可以尝试选择新鲜的、未经过多加工的海鲜，并且采用清蒸、水煮等清淡的烹饪方式，同时注意控制食用量。另外，吃完海鲜后适当饮水，保持规律的血压监测，观察血压变化情况。如果后续多次出现类似情况，建议记录饮食日记，就诊时可以提供给医生，帮助更精准地调整你的血压管理方案。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ8EZX61CNV4GR2VJETE','科普咨询','饮食与血压关联咨询','{"回答标签": ["专业指导", "详细解答"], "场景标签": ["饮食与血压"], "患者标签": [], "补充标签": [], "患者发言标签": ["咨询本人", "疑问语气"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:42:53.099173+08','场景描述根据患者提问内容提炼；患者提问保留原问题；回复案例直接使用提供的内容，无敏感信息无需脱敏；无回复规则内容',1.0000,'ce5d897d9dab9bef9b0cc32620f01505','success',NULL,'20260210153948'),
	 ('01KH0YXDT3M38SDM6M7QBW0KPP','55岁脑梗患者，有规律服用[拜阿斯匹灵]、少吃盐、睡眠良好的习惯，14天血压趋势上升，本次告知今日血压为129/70mmHg，脉搏72次/分，血压达标，脉搏正常。','请记录我今天的血压：高压129，低压70，脉搏72','你能主动监测并告诉我血压情况，这个习惯非常棒！已经帮你记录了今天的血压数据：129/70mmHg，脉搏72次/分。从数值来看，目前的血压处于正常范围，脉搏也在理想区间，整体情况不错。
不过单次血压测量结果并不能完全反映血压的长期控制情况，建议你继续坚持定期监测并记录，这样能更全面地了解自己的血压变化规律。为了让你更直观地了解近期血压趋势，你可以查看血压趋势图。
考虑到你正在关注血压健康，了解更多相关知识对管理血压很有帮助，这里有专业可靠的健康科普文章推荐给你。同时，如果你需要就诊，也可以通过门诊排班表了解医生近一个月的门诊安排，方便你提前规划就诊时间。

