scheduleStartDay=[日期], scheduleEndDay=[日期]',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYFMHS63WQAM5S3V8RFB','记录血压','血压及脉搏数据记录','{"回答标签": ["语气友好", "有推荐文章", "带排班"], "场景标签": ["血压记录", "脉搏记录"], "患者标签": ["72岁", "高血压", "糖尿病", "脑梗", "高脂血", "视力模糊", "不规律服药", "血压夜间高趋势", "血压达标", "脉搏正常"], "补充标签": ["慢病管理"], "患者发言标签": ["告知信息", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-09 18:26:01.796505+08',NULL,'场景描述结合患者年龄、基础疾病、用药情况、血压趋势、症状及本次提供的血压脉搏数据整理；患者提问将患者告知血压脉搏的表述明确为记录需求；回复案例对具体日期进行脱敏处理，其余内容保留原文；根据患者发言判断场景为记录血压',0.9500,'037a82565acc31bb19accf23b517b414','success','null',NULL),
	 ('01KH37W0518VB530CR75TEZDZ9','用户代家属咨询脚肿的处理办法','张医生，您好，我妈妈脚肿了该怎么办？','脚肿确实需要引起重视，尤其是对于高血压人群来说，可能与多种因素有关。首先想了解一下，除了脚肿之外，是否还有其他不舒服的症状？比如有没有觉得走路时脚踝发沉、鞋子变紧，或者按压脚踝会有凹陷很久不恢复的情况？另外，最近的血压控制情况怎么样？

脚肿可能的原因有很多，比如长时间站立或坐着导致的静脉回流不畅，也可能是某些药物的副作用，或者与心脏、肾脏功能有关。如果是突然出现的肿胀，或者伴随有胸闷、气短、尿量减少等情况，建议及时就医检查，让医生通过详细检查来判断具体原因。

在日常生活中，可以注意避免长时间保持同一姿势，适当抬高下肢促进血液回流，选择宽松舒适的鞋子。不过这些只是一般性建议，具体的原因还需要医生进行专业评估。建议尽快带她去医院做个检查，比如尿常规、肾功能和下肢血管超声等，这样才能更准确地找出问题所在并进行针对性处理。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ8JTDP4J9W97DY45C9N','诊疗相关','咨询症状处理办法','{"回答标签": ["专业建议", "引导进一步检查"], "场景标签": ["症状咨询"], "患者标签": ["家属脚肿"], "补充标签": [], "患者发言标签": ["代家属咨询", "求助语气"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:43:09.084012+08','场景描述根据用户代家属咨询脚肿处理办法的情况提炼；患者提问将原发言改写为完整清晰的问题，同时对敏感姓名脱敏；回复案例按脱敏规则处理后保留原文内容；结合用户咨询家属脚肿处理的需求确定场景和子场景',0.9500,'941c2c8f830a6ac4de2fd1a0b191b9f0','success',NULL,'20260210153948'),
	 ('01KH37W052ZTXMKZDPZJTD3W8H','患者告知此前在[医院]住院期间，经肾内科会诊被诊断为痛风，此前患者曾咨询家属脚肿的相关问题','我想告知您，住院的时候，肾内科会诊，说是痛风。','痛风是一种由于嘌呤代谢紊乱导致血尿酸升高，尿酸盐结晶沉积在关节及周围组织引起的疾病。确诊痛风后，日常需要注意低嘌呤饮食，避免食用动物内脏、海鲜、浓肉汤等高嘌呤食物，同时要多喝水，有助于尿酸的排泄。不过具体的饮食方案和生活方式调整，建议你咨询肾内科医生，他们会根据你的具体情况给出更详细的指导。另外，如果有任何需要记录的数据（如血压、服药信息等）、心血管方面的健康疑问，都可以随时告诉我，我会为您提供专业的建议和帮助。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ8M35CKRYR9AMMAT5PM','诊疗相关','病情告知','{"回答标签": ["专业指导", "建议转诊咨询"], "场景标签": ["病情告知"], "患者标签": ["家属有痛风"], "患者发言标签": ["陈述病情", "咨询家属情况"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:43:14.773847+08','场景描述结合患者历史咨询家属脚肿的问题及本次告知的痛风诊断信息，脱敏后整理；患者提问将患者的陈述转化为清晰的告知类表述；回复案例按原文保留，未涉及敏感信息无需脱敏；根据患者当前是告知确诊痛风的情况确定场景与子场景',0.9000,'dd36f1c6d8283ef63aff1b8203997af4','success',NULL,'20260210153948'),
	 ('01KH3B53XT0XCAGKP1GB4RESWG','患者咨询购买到不同厂家的同款药物能否服用，医生给出一般不建议更换厂家的初步回复','我买的药厂家不一样可以吃吗？','不同厂家生产的同一种药物，只要药品通用名称一致、规格相同、剂型相同，理论上主要成分和治疗作用是一致的，一般可以服用。不过由于生产工艺、辅料成分等可能存在差异，不同厂家的药物在吸收、疗效和不良反应方面可能会有细微差别。 

服用前建议仔细核对药品的通用名称、规格、用法用量是否与医生处方一致，查看药品有效期和外观是否正常。如果是第一次更换厂家，服用期间可以多留意身体反应，观察血压控制情况以及是否有不适症状。如果对药物有任何疑问，或者服药后感觉不适，建议及时咨询医生或药师，由他们根据你的具体情况进行评估和建议。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ6RP9JTVVY0TV2RBVK6','药物相关','不同厂家同款药物服用咨询','{"回答标签": ["直接回答"], "场景标签": ["药物服用咨询"], "患者标签": [], "补充标签": [], "患者发言标签": ["语气疑惑", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-10 16:37:13.233333+08','2026-02-10 16:38:58.154085+08','场景描述基于患者咨询不同厂家药物能否服用及医生初步回复的内容整理；患者提问是将患者的口语化表述改写为通顺清晰的问题；回复案例直接使用给定内容，未做修改；场景和子场景根据患者咨询的药物相关内容判定',0.9500,'b04fe14eee54113de717ed7580421997','success',NULL,'20260210163713');
INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH37W05THE79XCERG054DVWM','患者反馈无法手动添加厂家/商品名，向数字分身求助','厂家/商品名还是无法手动添加，该怎么办？','我是医生的数字分身，可以智能响应您的健康需求。目前主要专注于高血压慢病相关的健康管理服务，关于商品添加等非健康问题我无法提供帮助。有高血压方面的健康疑问，比如血压监测、饮食调理、运动建议等，都可以随时告诉我，我会为你提供专业的健康指导。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZABFG7JZEKNAZB25H77','其它场景','非健康类问题咨询','{"回答标签": ["明确服务范围", "引导健康问题咨询"], "场景标签": ["非健康问题咨询"], "患者标签": [], "补充标签": [], "患者发言标签": ["咨询非健康问题", "陈述问题"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:45:22.257205+08','场景描述根据患者发言和回复案例整理，明确患者的问题场景；患者提问结合发言原意补充完整问题；回复案例按原文保留，无敏感信息无需脱敏；场景判断为非健康相关的其它场景，子场景定为非健康类问题咨询',0.9500,'f4aefa5609634d35152b7642573d5046','success',NULL,'20260210153948'),
	 ('01KH0Z0CPPBR7PT20GWY8N1PGW','72岁的高血压、冠心病、脑梗、高脂血症患者，有胸痛症状，本次告知自己的血压为高压167mmHg、低压89mmHg，属于中度偏高，脉搏72次/分，为正常范围。','我今天的血压是高压167，低压89，脉搏72，请帮我记录并给出相关建议','你能主动监测并告诉我血压情况，这个习惯非常棒！我已经帮你记录了这次的血压数据。
你今天测量的血压中，**高压167属于中度偏高**，这个数值需要引起重视。血压明显升高可能会增加心脑血管负担，建议你尽快到[医院]就诊，让医生评估当前状况。
为了帮助医生更全面了解你的血压情况，你可以通过门诊排班工具查看近期医生出诊信息，提前做好就诊安排。

