articleId=891, articleTitle=高压高，低压正常，是高血压吗？, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/4ddbbf52fad8a79dc352fe2fe2c2337a.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=VOICcaoruBOV51M9v3E9Vhe3S80%3D&response-content-disposition=inline&image_process=resize,l_300',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYGNJJXXQCDQYYRJAQRZ','记录血压','告知血压及脉搏数值请求记录','{"回答标签": ["语气友好", "有推荐文章"], "场景标签": ["血压记录", "脉搏记录"], "患者标签": ["64岁", "高血压", "糖尿病", "夜尿增多", "不规律服药", "血压达标", "脉搏正常"], "补充标签": ["血压波动较大"], "患者发言标签": ["陈述事实", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-09 18:27:30.861784+08',NULL,'场景描述结合上下文的患者年龄、疾病、症状、服药情况、血压波动情况及本次的血压、脉搏数值整理；患者提问根据当前患者发言补充记录的动作意图改写；回复案例对其中的具体日期进行脱敏处理；场景根据患者发言为告知血压数值判断为记录血压场景，子场景进一步明确为告知血压及脉搏数值请求记录',0.9500,'10293eb38764fa77c2e6c6e4d3eb123c','success','null',NULL),
	 ('01KH37W05ABNJ5Z29SPSGKS406','长期在外地的患者咨询如何通过互联网开具检查单','你好，我长期在外地，请问怎么用互联网开检查单？','作为医生的数字分身，当前可以为你提供高血压慢病健康管理及科学指导，互联网开检查单属于具体就医流程问题，暂无法直接协助。建议你通过就诊医院的官方线上平台（如医院官网、官方APP或公众号）查询相关服务，或直接联系你的主治医生团队咨询具体流程，他们会根据你的健康状况和实际需求提供专业指导。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZ9AH2GX4BZKMWQYC0A4','院内资源/政策咨询','互联网开检查单流程咨询','{"回答标签": ["直接告知无法协助", "提供解决建议"], "场景标签": ["互联网开检查单", "就医流程咨询"], "患者标签": ["长期异地"], "补充标签": [], "患者发言标签": ["咨询本人", "语气礼貌"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:43:56.212843+08','场景描述、患者提问根据当前患者发言提取改写，未涉及敏感信息无需脱敏；回复案例直接使用提供的内容，无敏感信息无需修改；根据患者咨询线上开检查单的需求判定场景为院内资源/政策咨询，子场景为互联网开检查单流程咨询',1.0000,'e75ff9a7c3c99503bb2692afdb616ca5','success',NULL,'20260210153948'),
	 ('01KH37W05Q6X6YHNMQDCYSEZX3','患者此前提及上周末没挂到号，本次仅发送“本周日”，未明确具体需求。','本周日有什么相关的就医相关问题可以咨询或有什么就医相关的安排？','您提到"本周日"，是有什么具体的健康相关问题想咨询吗？比如血压监测情况、用药相关疑问，或者是想了解周末期间的高血压管理注意事项？可以具体说明一下，我会根据您的情况提供相应的健康建议。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZA2ABV5S3G5MSNF8Q27','其它场景','需求不明确的咨询','{"回答标签": ["引导明确需求"], "场景标签": ["需求不明确"], "患者标签": ["有挂号诉求"], "补充标签": [], "患者发言标签": ["表述模糊", "咨询就医相关"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:45:12.981438+08','场景描述结合聊天历史中患者提及上周末没挂到号以及本次仅发送“本周日”的情况生成；患者提问结合患者历史挂号相关诉求及本次模糊表述改写为明确的疑问；回复案例按要求保留原文未做额外修改；因患者仅发送“本周日”未明确具体需求，故判断为其它场景下需求不明确的咨询',0.7000,'ebb7ef1cade5273d6f0f0c0a8deeb6b8','success',NULL,'20260210153948'),
	 ('01KH37W05XRP1B4PAVPMR1T12D','患者告知自己饭后走动了叁仟多米','饭后走动了叁仟多米','饭后适当走动是个很好的习惯，对控制血压和血糖都有帮助。不过要注意根据自己的身体状况调整运动强度，避免过度劳累。如果有高血压，建议保持规律的轻度活动，比如每天快走30分钟左右，这样更有利于血压的长期管理。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZAJ42C5MWKRW63ZGRJX','其它场景','生活习惯分享','{"回答标签": ["健康指导"], "场景标签": ["生活习惯分享"], "患者标签": [], "补充标签": [], "患者发言标签": ["陈述事实"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:45:42.120098+08','场景描述和患者提问均根据患者当前发言直接整理，回复案例直接使用给定内容并按要求未修改医学相关内容，无敏感信息需要脱敏',1.0000,'3104a0bce26c726c40586c04cc4f9406','success',NULL,'20260210153948'),
	 ('01KH37W061F74TK4KR7DYS7K6J','患者告知自己喝了点酒，无其他症状或病史相关信息提及','我喝了点酒，需要相关健康建议吗？','对于高血压人群来说，饮酒可能会导致血压波动，增加心血管负担。建议尽量避免饮酒，养成健康的生活习惯有助于更好地控制血压。如果有高血压相关的健康问题，我可以为你提供科学的管理建议。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZAQVB0960Y9P5828KSM','其它场景','生活习惯告知','{"回答标签": ["健康建议"], "场景标签": ["生活习惯"], "患者标签": [], "补充标签": [], "患者发言标签": ["陈述告知"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:45:48.732149+08','场景描述基于患者仅告知喝了点酒的内容；患者提问结合患者发言补充为明确的需求询问；回复案例按要求保留原内容未改写；无敏感信息需脱敏',0.7000,'14a73da10c0f84cc217eb2e2adc153a4','success',NULL,'20260210153948');
INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH37W060R15YAWVGQ9RVCRAW','患者此前提及术后躺着睡觉经常胸口堵得慌，此次补充说明该不适仅在躺着睡觉的时候出现','我只有躺着睡觉的时候会出现胸口堵得慌的情况，这是怎么回事？','注意到你的问题似乎没有完整描述。躺着睡觉时具体有什么不适症状吗？比如是否有头晕、胸闷、呼吸困难或其他感觉？这些信息对判断可能的原因很重要。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZANVZF0QXBWG7KTWY9B','诊疗相关','术后症状咨询','{"回答标签": [], "场景标签": ["术后症状咨询"], "患者标签": ["术后患者", "有胸口堵症状"], "补充标签": [], "患者发言标签": ["补充症状发作场景", "咨询本人症状"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:45:51.056661+08','场景描述结合患者历史发言和当前补充发言整理，患者提问结合历史发言中提到的术后胸口堵的症状和当前补充的发作场景改写，回复案例按要求保留原内容未修改',0.9500,'ee0dc53c2ca2efa148b2683b8736a383','success',NULL,'20260210153948'),
	 ('01KH0Z2FM14KA5MXPV6ST71YCJ','67岁的冠心病、高脂血、脑梗患者，有胸痛症状，规律服用盐酸贝尼地平片、阿托伐他汀、拜阿斯匹灵，存在7天血压趋势夜间高的情况，本次告知今日血压为129/70mmHg，脉搏72次/分，血压达标，脉搏正常。','记录我今日的血压：高压129，低压70，脉搏72','你能主动监测并记录血压，这个习惯非常好，已经帮你保存了今天的血压记录。今天的血压129/70mmHg，脉搏72次/分，整体处于正常范围。不过单次血压测量结果可能受多种因素影响，建议你继续坚持规律监测，这样能更全面地了解自己的血压状况。
了解医生的门诊时间可以帮助你更合理地安排复诊，以下是医生近一个月的门诊排班信息，你可以查看具体安排。

scheduleStartDay=[日期], scheduleEndDay=[日期]
