[未知类型(tool_articles): {"type": "tool_articles", "tool_articles": [{}]}]',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZB11VZY32VEYSB3DF44','诊疗相关','血压情况咨询','{"回答标签": ["语气友好", "有就诊引导", "有推荐学习内容"], "场景标签": ["血压咨询"], "患者标签": ["血压正常范围偏低", "脉搏正常"], "补充标签": [], "患者发言标签": ["咨询本人", "表述客观"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:46:39.17257+08','场景描述结合患者提供的血压脉搏数据，按照血压和脉搏的判定规则进行总结；患者提问根据患者表述的血压脉搏数值及疑问改写为完整清晰的问题；回复案例对其中的具体日期进行脱敏处理，替换为[日期]占位符；场景根据患者咨询血压情况的内容判定为诊疗相关下的血压情况咨询子场景',0.9500,'5219a52ba2a16b759bc999de2eca6341','success',NULL,'20260210153948'),
	 ('01KH37W062960R68G6RC8SPAT3','患者此前咨询小程序操作相关问题，被告知无法回复此类问题后，回复表示认同','嗯嗯，是的','看起来你是想继续我们的健康咨询。作为医生的数字分身，我可以为你提供高血压慢病管理相关的专业指导。有什么具体的健康问题想了解吗？比如血压监测、饮食调整、运动建议或者用药方面的疑问，都可以告诉我。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZATDXT9FN5VC8ZHX9FV','其它场景','对无法回复的告知表示认同','{"回答标签": ["引导医学咨询", "明确服务范围"], "场景标签": ["小程序操作咨询", "慢病管理咨询引导"], "患者标签": [], "补充标签": [], "患者发言标签": ["语气认同", "非医学问题回应"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:46:41.94875+08','场景描述结合聊天历史和当前患者发言整理，患者提问直接采用当前患者发言，回复案例直接使用提供的内容，均未涉及敏感信息无需脱敏',1.0000,'cf3916c046eed303bed4184c517a338d','success',NULL,'20260210153948'),
	 ('01KH0Z2NJWW49Y7YRVWXQAGCRH','55岁高血压患者，规律服用[苯磺酸氨氯地平片]，28天血压趋势无显著变化，本次告知今日血压为129/70mmHg，脉搏72次/分，血压达标，脉搏正常。','我今天的血压高压129，低压70，脉搏72，请记录','你能主动监测并告诉我血压情况，这个习惯非常棒！你的血压129/70mmHg，脉搏72次/分，目前这个数值处于正常范围。我已经帮你记录了这次的血压数据。不过单次血压测量结果可能受多种因素影响，建议你继续坚持规律监测血压，比如每周测量3-4天，每天早晚各测量一次，这样能更全面地了解自己的血压状况。为了让你更直观地了解近期血压变化趋势，你可以通过查看门诊排班信息，提前规划就诊时间，和医生详细沟通血压管理情况。scheduleStartDay=[日期], scheduleEndDay=[日期]content=同时，关于高血压的日常管理，还有很多需要了解的知识，你可以看看相关的科普文章，帮助你更好地控制血压。articleId=512, articleTitle=高压145mmHg，低压60mmHg，我到底是高血压？还是低血压？, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/ae4068ae4314789aa8d9e5b0820d1750.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=HX3xzUt0gqdyouXJEcFJqt%2FuIHg%3D&response-content-disposition=inline&image_process=resize,l_300articleId=870, articleTitle=血压高一点儿，但又不到高血压的标准？, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/2efecc5c6504a21351c22745d88f3310.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=VjdsxhknfzM0V18P5swJdUwyf7M%3D&response-content-disposition=inline&image_process=resize,l_300articleId=891, articleTitle=高压高，低压正常，是高血压吗？, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/4ddbbf52fad8a79dc352fe2fe2c2337a.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=VOICcaoruBOV51M9v3E9Vhe3S80%3D&response-content-disposition=inline&image_process=resize,l_300',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYGV964EFB99VT2XCNYM','记录血压','告知血压及脉搏数据请求记录','{"回答标签": ["语气友好", "有推荐文章"], "场景标签": ["血压记录"], "患者标签": ["55岁", "高血压", "规律服药", "血压达标", "脉搏正常"], "补充标签": [], "患者发言标签": ["陈述告知", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-09 18:27:41.275882+08',NULL,'场景描述结合患者年龄、高血压病史、用药情况、血压趋势及本次血压脉搏数据生成；患者提问根据患者告知血压脉搏的发言改写为记录请求；回复案例对其中具体日期进行脱敏处理；其余内容均来自上下文信息',1.0000,'135a61360ce267b764a0a1842f7acc99','success','null',NULL),
	 ('01KH37W061T6KN4NR33E2RYB0S','患者复查后发现甲功数值升高，咨询数值升高的原因以及日常注意事项','你好，请问这次复查我的甲功数值升了，是什么原因导致的？我平时要注意哪方面？','甲状腺功能指标升高确实会让人有些担忧，这种情况在临床上比较常见，可能的原因有很多种。甲状腺功能指标包括TSH（促甲状腺激素）、T3（三碘甲状腺原氨酸）、T4（甲状腺素）等不同项目，不同指标升高的意义和原因也有所不同。比如TSH升高可能提示甲状腺功能减退，而T3、T4升高则可能与甲状腺功能亢进有关。

导致甲状腺功能指标变化的原因可能包括自身免疫性甲状腺疾病（如桥本甲状腺炎、Graves病）、甲状腺结节或肿瘤、药物影响、碘摄入异常、应激状态、感染等多种因素。具体原因需要结合你的完整检查报告（包括各项指标的具体数值、参考范围）、症状表现（如是否有体重变化、心慌、出汗、疲劳、怕冷或怕热等）以及既往病史等信息，由内分泌科医生进行综合判断。

在日常生活中，你可以注意以下几点：保持规律作息，避免过度劳累和精神压力；注意均衡饮食，避免过量摄入高碘食物（如海带、紫菜等）或严格限碘，具体饮食调整建议需根据你的具体病情而定；记录自己的症状变化，如体重、心率、情绪等，下次就诊时提供给医生，帮助医生更全面地评估你的情况。

不过需要提醒的是，以上建议仅为一般性指导，不能替代专业医疗诊断和治疗。甲状腺功能异常需要由内分泌科医生进行专业评估，明确诊断后再制定个体化的治疗和随访方案。建议你尽快携带完整的检查报告到内分泌科就诊，以便明确原因并及时处理。

另外，我是心血管内科医生的数字分身，主要专注于高血压等心血管慢病的健康管理。如果你有任何关于血压监测、心血管健康方面的问题，或者需要记录血压、用药等健康数据，都可以随时告诉我，我会为你提供专业的建议和帮助。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZARSQ0J3MBEWF73CYR0','咨询其它科室问题','甲状腺功能指标异常咨询','{"回答标签": ["专业严谨", "未直接回答患者问题", "有就诊引导"], "场景标签": ["甲状腺功能异常咨询"], "患者标签": ["甲功数值升高"], "补充标签": ["跨科室咨询"], "患者发言标签": ["咨询他人", "语气平和", "就医后咨询"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:46:00.933409+08','场景描述根据患者发言中提到的复查甲功数值升高，咨询原因和注意事项的内容整理；患者提问将原发言调整为语句通顺、表意完整的问题；回复案例按要求保留原内容，未涉及敏感信息无需脱敏；无回复规则内容，故省略。',0.9500,'0c08fbc15b6c2e7cd1ba533b65bfaa5c','success',NULL,'20260210153948');
INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH0Z56T79MS0ZS7FP088G638','40岁冠心病患者，有胸痛症状，7天血压趋势上升，无服药数据，本次测量血压为129/70mmHg，达标，脉搏72次/分，正常。该患者属于冠心病患者出现胸痛症状，需预警，尽快回院。','请帮我记录今天的血压：高压129，低压70，脉搏72','你能主动监测并告诉我，这个习惯非常棒！我已经帮你记录下这次的血压数据了：高压129，低压70，脉搏72。从血压评级来看，你的血压处于正常范围呢，脉搏也在正常的静息心率区间（60-100次/分钟）内，整体情况不错。不过单次的血压测量可能会受到很多因素的影响，比如测量时的情绪、刚刚是否有运动等，所以建议你继续保持监测血压的习惯，这样能更全面地了解自己的血压波动情况。另外，我为你推荐一篇相关的科普文章，你可以点击查看，了解更多关于血压监测和管理的知识。

