INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH37W07SJCTSC03J2TVKTDQT','有早搏、心动过缓病史的患者，近半个月出现5次低压偏低（60mmHg以下）、19次心率在50-60次/分的情况，咨询回院复诊时的合适用药及降压药剂量是否需要调整','我有早搏、心动过缓的病史，近半个月来测血压有5次低压在60mmHg以下，心率有19次在50-60次/分，下次回院复诊时应服哪些药物较合适？降压药的剂量是否需要调整？请帮忙向医生反馈我的情况','注意到你提到最近半个月有5次舒张压低于60mmHg，19次心率在50-60次/分之间，结合你有早搏和心动过缓的病史，这些情况需要引起重视。心率偏慢和血压偏低可能与心脏功能、药物作用或其他健康因素有关，尤其是同时出现时，建议尽快到心内科门诊进行评估。关于药物调整和后续用药方案，这需要医生根据你的具体检查结果、当前用药情况、心率和血压波动特点等综合判断，不能仅凭线上描述来确定。建议复诊时携带近期的血压和心率记录，以便医生更全面地了解你的情况。在复诊前，注意监测血压和心率的变化，记录具体数值和测量时间，如果出现头晕、乏力、眼前发黑等不适症状，应及时就医。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZCZMRR1Z3Y5B7NRQMXX','诊疗相关','咨询调整用药','{"回答标签": ["专业建议", "引导线下就诊"], "场景标签": ["用药调整咨询", "血压异常咨询", "心率异常咨询"], "患者标签": ["有早搏病史", "有心动过缓病史", "低压偏低", "心率偏慢"], "补充标签": [], "患者发言标签": ["咨询本人情况", "诉求明确"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:52:07.427493+08','场景描述结合患者的病史、近半个月的血压心率异常情况及咨询需求整理，患者提问保留患者原意，将患者的情况说明和诉求整合为清晰的问题，回复案例按原文保留未做修改，无回复规则故留空',0.9500,'f2817f695092c27c48bb3b2c8d726edf','success',NULL,'20260210153948'),
	 ('01KH37W080VT53HTZ35VFTHKN6','患者询问[姓名]医生是否在群里，并咨询服用阿司匹林肠溶片后腿上出现淤青的相关问题','1. [姓名]医生在群里吗？2. 我这个月吃阿司匹林肠溶片后腿上有淤青，这是怎么回事？该怎么处理？','阿司匹林是常用的抗血小板药物，它通过抑制血小板聚集来预防血栓形成，但同时也可能增加出血风险，皮肤淤青就是常见的轻微出血表现之一。这种情况在服药期间比较常见，但仍需要关注和适当处理。

出现淤青时，首先要注意观察淤青的大小、数量以及是否有其他部位的出血表现，比如牙龈出血、鼻出血、大便发黑等。如果只是偶尔出现小面积淤青，没有其他不适，可以继续观察，但要避免剧烈运动和碰撞。

为了帮助你更全面地了解阿司匹林的用药注意事项和可能的不良反应，你可以查看药品说明书获取详细信息。

[未知类型(tool_drug_instruction): {"type": "tool_drug_instruction", "tool_drug_instruction": {"drug_generic_id": "7EZndTQ12J6", "drug_generic_name": "阿司匹林肠溶片", "indication": "抑制下述情况时血小板粘附和聚集

•不稳定性心绞痛（冠状动脉血流障碍所致的心脏疼痛）；

•急性心肌梗塞；

•预防心肌梗塞复发；

•动脉血管的术后（动脉外科手术介入后，如主动脉冠状动脉静脉搭桥术，PTCA）；

•预防大脑一过性的血流减少（TIA：短暂性脑缺血发作）和出现早期症状（如面部或手臂肌肉一过性瘫痪或一过性失明）后预防脑梗塞。", "show_add_drug_button": true}}]

如果淤青频繁出现、面积较大，或者伴随其他出血症状，建议及时就医，医生可能会根据情况调整药物剂量或进行相关检查，比如血常规、凝血功能等，以评估出血风险。用药调整需要医生根据具体情况判断，不要自行停药或更改剂量。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZD65V044KSD1NVC9ZAJ','药物相关','药物不良反应咨询','{"回答标签": ["医学科普", "给出处理建议"], "场景标签": ["药物不良反应咨询"], "患者标签": ["服用阿司匹林肠溶片", "腿部淤青"], "补充标签": [], "患者发言标签": ["咨询本人情况", "求助语气"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:52:50.861524+08','场景描述根据患者发言整理，对医生姓名进行脱敏；改写患者提问将患者的两部分诉求明确为清晰的问题；回复案例仅对敏感信息进行脱敏，保留原内容；根据患者咨询服药后出现不良反应的内容确定场景和子场景',0.9500,'997aa05c96c071de0e9136ff8cc9d37b','success',NULL,'20260210153948'),
	 ('01KH37W087QBJKEX4EPP9Y1J9B','患者前几日在[医院]开具药物，服用三天后出现胃部不适，患者本身有复合型溃疡病史，开药时未告知医生该病史，查看药物说明发现此药对肠胃刺激性大，剩余药量还有约一个月，前来咨询能否调换药物。','您好，我前几日在[医院]开的药，吃了三天后胃不舒服，我有复合型溃疡病史但开药时没告诉医生，看说明这个药对肠胃刺激性很大，现在还有差不多一个月的药量，请问能不能给我调换药物？','确实，有胃溃疡病史的话，选择降压药时需要特别注意对胃肠道的影响。你现在的情况需要调整用药方案，不过具体的药物调整必须由医生根据你的血压控制情况、溃疡严重程度以及其他健康状况来综合判断。

建议你尽快联系开药的医生或者到消化内科就诊，详细说明你的胃溃疡病史和目前用药后的胃部不适症状。医生会根据你的具体情况评估是否需要更换降压药物，或者同时给予胃黏膜保护治疗。

另外，记得带上你正在服用的降压药包装和之前的胃镜检查报告（如果有的话），这些信息会帮助医生更准确地为你调整治疗方案。千万不要自行停药或更换药物，以免影响血压控制或加重胃部不适。',NULL,'01KGKT1RS0776XC90KCMGKG2J9','01KGPFEZDAS5RBNZBBNGSV9HQ9','药物相关','咨询调整用药','{"回答标签": ["给出就医建议", "提醒勿自行换药"], "场景标签": ["调药咨询"], "患者标签": ["复合型溃疡病史", "服药后胃部不适"], "补充标签": [], "患者发言标签": ["语气礼貌", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-10 15:39:48.693654+08','2026-02-10 15:53:06.852505+08','场景描述和患者提问均根据当前患者发言内容整理，对敏感信息[医院]进行脱敏，保留患者有复合型溃疡病史、服药后胃部不适、剩余药量、咨询调药的核心信息；回复案例仅对其中的医院信息进行脱敏处理，保留原有回复内容。',0.9500,'91ad9d9a8ea4ce571f38b9a38be4f748','success',NULL,'20260210153948'),
	 ('01KH0Z937DCJ88P9R9CS4PRTH7','40岁冠心病患者，规律服用[盐酸贝尼地平片]，有少吃盐、运动的习惯，14天血压趋势下降，本次告知今日血压为129/70mmHg，脉搏72次/分钟，血压达标，脉搏正常。','请记录我今日的血压：高压129，低压70，脉搏72','你能主动监测并告诉我，这个习惯非常棒！我已经帮你记录了今天的血压数据。今天的血压值是129/70mmHg，脉搏72次/分钟，这个数值在正常范围内，说明目前血压控制得不错。不过单次测量的结果不能完全代表整体情况，建议你继续坚持规律监测，记录更多数据，这样能更全面地了解血压变化趋势。为了让你更好地了解血压管理的相关知识，我为你推荐专业可靠的健康科普文章。

