content=

请务必按照医生或药师的指导服用药物，以确保用药安全和治疗效果。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYXXNT7BSJ2ZFT1VXN5H','药物相关','服药时机咨询','{"回答标签": ["引导咨询专业人员", "推荐科普文章"], "场景标签": ["服药时机咨询"], "患者标签": ["45岁", "高脂血症", "肌肉不适", "血压轻度偏高", "不规律服药"], "补充标签": ["他汀类药物服用咨询"], "患者发言标签": ["咨询本人", "疑问语气"]}',NULL,NULL,NULL,NULL,'2026-02-10 17:39:22.17348+08','2026-02-10 17:42:50.637447+08','场景描述根据上下文信息里的患者年龄、疾病、用药、症状、血压情况及当前提问整合；患者提问根据当前发言改写为完整清晰的问题；回复案例按要求保留原内容仅对敏感信息检查后确认无需额外脱敏；根据患者咨询药物服用时机确定场景及子场景；标签从场景描述、患者情况、发言及回复内容提取。',0.9500,'b07582f90b23c765e225c46baf1d60f2','success',NULL,'20260210173922'),
	 ('01KH3EPXGA0NSGVF4N2WF3PRWR','35岁的高血压患者，规律服用[苯磺酸氨氯地平片]，日常有少吃盐、运动、不抽烟的健康习惯，此次告知自己当日的血压为129/70mmHg，脉搏72次/分钟，血压达标，脉搏正常。','我今天的血压高压129，低压70，脉搏72，请记录','你能主动监测并告诉我血压情况，这个习惯非常棒！我已经帮你记录下今天的血压数据：129/70 mmHg，脉搏72次/分钟。从单次测量结果来看，你的血压处于正常范围内，脉搏也在正常区间，整体情况良好。不过单次血压数据有一定局限性，为了更全面地了解你的血压状况，建议你继续坚持定期监测并记录，特别是注意不同时间段（如早晨起床后、晚上睡前）的血压变化。  

了解医生的门诊时间安排有助于你更方便地进行复诊，你可以查看以下门诊排班信息。  


scheduleStartDay=[日期], scheduleEndDay=[日期]
content=

关于高血压的日常管理，还有很多需要了解的知识，推荐你阅读相关的健康科普文章，帮助你更好地控制血压。  


articleId=512, articleTitle=高压145mmHg，低压60mmHg，我到底是高血压？还是低血压？, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/ae4068ae4314789aa8d9e5b0820d1750.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=HX3xzUt0gqdyouXJEcFJqt%2FuIHg%3D&response-content-disposition=inline&image_process=resize,l_300
articleId=870, articleTitle=血压高一点儿，但又不到高血压的标准？, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/2efecc5c6504a21351c22745d88f3310.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=VjdsxhknfzM0V18P5swJdUwyf7M%3D&response-content-disposition=inline&image_process=resize,l_300
articleId=891, articleTitle=高压高，低压正常，是高血压吗？, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/4ddbbf52fad8a79dc352fe2fe2c2337a.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=VOICcaoruBOV51M9v3E9Vhe3S80%3D&response-content-disposition=inline&image_process=resize,l_300',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYCTFTMZP9MJQRZJRW15','记录血压','记录当日血压脉搏数据','{"回答标签": ["语气友好", "有推荐文章"], "场景标签": ["血压记录", "脉搏记录"], "患者标签": ["35岁", "高血压", "规律服药", "血压达标", "脉搏正常"], "补充标签": [], "患者发言标签": ["陈述告知", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-10 17:39:22.17348+08','2026-02-10 17:43:09.547935+08','场景描述结合上下文的患者年龄、疾病、用药、习惯及本次提供的血压脉搏数据生成；患者提问将患者告知血压脉搏的表述明确为记录请求；回复案例对其中的具体日期进行脱敏处理；其余内容均依据上下文信息及给定内容整理。',0.9500,'52a83b66a68640d7a23d2882e253609f','success',NULL,'20260210173922'),
	 ('01KH3EPXGKHZ206ZRG1982REZM','45岁高脂血症患者，服用[阿托伐他汀]，出现肌肉无力症状，今日自测血压为167/89mmHg，属于中度偏高，脉搏72次/分，为正常范围，需预警尽快回院','我今天的血压高压167，低压89，脉搏72，请记录','你能主动监测并告诉我血压情况，这个习惯非常棒！已经帮你记录了今天的血压数据。
你今天测量的血压值为167/89mmHg，这个血压值属于**明显偏高**的范围，需要引起重视。血压持续升高可能会增加心脑血管疾病的风险，建议你尽快到医院就诊，让医生评估当前的血压状况并调整治疗方案。
血压偏高时需要特别留意身体反应，你可以通过症状收集工具记录是否有头痛、头晕、胸闷等不适症状，这对医生诊断很有帮助。

为了方便你安排就诊，这里提供医生近一个月的门诊排班信息，你可以查看并选择合适的时间前往。

[门诊排班信息]

同时，你也可以阅读相关的健康科普文章，了解更多关于高血压管理的知识。

[高血压科普文章列表]',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYDCPYZCZXMMT361M211','记录血压','记录单次血压及脉搏数据','{"回答标签": ["建议就诊", "推荐文章"], "场景标签": ["血压记录", "中度偏高血压"], "患者标签": ["45岁", "高脂血症", "肌肉无力", "服用阿托伐他汀"], "补充标签": ["需预警"], "患者发言标签": ["陈述病情", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-10 17:39:22.17348+08','2026-02-10 17:43:38.748169+08','场景描述结合患者年龄、病史、症状、用药情况及本次自测的血压、脉搏数据，按规则判定血压状态并体现预警信息；患者提问将患者的陈述转化为明确的记录请求；回复案例将原文中的具体排班、文章信息脱敏为占位符，保留原意；根据患者发言内容判定场景为记录血压',0.9500,'1820480f60afae3896b9944cdb623be4','success',NULL,'20260210173922'),
	 ('01KH3EPXN32P39BABD93AQKAB9','45岁高脂血症患者，不规律服用[阿托伐他汀]，有运动习惯，近期半个月内出现5次低压低于60mmHg，19次心率在50-60次/分，既往有早搏、心动过缓病史，且两次血压对比波动较大，咨询下次回院复诊时的合适用药及降压药剂量是否需要调整。','请向[医生]反应一下，最近半个月我测血压有5次低压在60mmHg以下，心率有19次在50-60次/分，我既往有早搏、心动过缓病史，下次回院复诊时，应服哪些药物较合适？降压药的剂量是否需要调整？','你能主动关注并记录血压和心率的异常情况，这个意识非常好。从你描述的情况来看，最近半个月有5次舒张压低于60mmHg，19次心率在50-60次/分之间，结合你既往有早搏和心动过缓的病史，这些数据确实需要引起重视。心率偏慢和舒张压偏低可能与多种因素有关，包括药物影响、身体状态变化等。你目前正在服用的阿托伐他汀钙片是调节血脂的药物，一般不会直接影响心率和血压，但降压药物的使用确实需要根据血压变化进行评估。关于下次复诊时的用药调整，包括降压药剂量是否需要调整，这需要医生结合你的全面情况来判断，包括血压心率的具体波动规律、症状表现、目前用药方案以及相关检查结果等。**药物的调整必须由医生面诊后决定，不建议自行调整剂量或更换药物**。建议你在复诊前继续监测并记录血压和心率，尤其是出现不适症状时的数值变化，同时记录目前正在服用的所有药物名称和剂量，这些信息对医生的评估会很有帮助。复诊时可以详细告知医生你观察到的这些异常情况，以便医生做出合适的用药调整方案。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYXZ0W0V2MZGRTYFBDY7','药物相关','咨询调整用药','{"回答标签": ["专业严谨", "引导就医"], "场景标签": ["低压偏低", "心率偏慢", "用药调整咨询"], "患者标签": ["45岁", "高脂血症", "早搏病史", "心动过缓病史", "不规律服药"], "补充标签": ["血压波动较大"], "患者发言标签": ["咨询本人", "诉求明确"]}',NULL,NULL,NULL,NULL,'2026-02-10 17:39:22.17348+08','2026-02-10 17:42:48.488956+08','场景描述结合上下文的患者基本信息、病史、用药情况、血压心率异常情况及本次提问内容整合；患者提问对敏感信息[周荣医生]脱敏为[医生]，保留原意并整理为清晰问题；回复案例按要求仅脱敏敏感信息，保留原内容；结合患者提问内容判断场景为药物相关下的咨询调整用药。',0.9500,'25e362665257f67e3ac002e2d042cc73','success',NULL,'20260210173922');
INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH3EPXN4XFQWMZGGG8FCF5CK','45岁高脂血症患者，规律服用[阿托伐他汀]，血压两次对比波动不大，因看到网上关于高血压药服用时间的说法，对自己一直早上服用苯磺酸氨氯地平片的方式产生疑问，咨询该药物的正确服用时间。','服用苯磺酸氨氯地平片到底应该早上吃还是晚上吃？最近看到网上有的医生说治疗高血压的药应该晚上吃，因为早上是血压第一个高峰而且即使吃药了还有个半衰期，影响治疗效果。我以前一直都是早上吃，不知是否正确？','苯磺酸氨氯地平片的服用时间需要结合个人血压波动规律和医生建议来确定。从药物特性来看，它属于长效降压药，半衰期较长，理论上每天固定时间服用即可维持稳定的血药浓度。不过，确实有研究显示部分患者晚上服药可能更有利于控制夜间血压和晨峰血压，但这并非适用于所有人。
你之前习惯早上服用，且目前没有提到明显的血压波动问题，可以继续保持这一习惯。不过如果想调整服药时间，建议先通过动态血压监测了解自己24小时血压变化规律，再在医生指导下进行调整。突然改变服药时间可能会引起血压波动，需要特别注意。
用药方案的调整需要综合考虑个体情况，包括血压波动特点、合并疾病等因素。你可以查看药品说明书了解更多用药细节，同时建议在下次复诊时与医生详细沟通服药时间的问题，根据你的具体情况制定个性化方案。

[药物说明JSON]

需要注意的是，无论选择什么时间服药，**保持规律服用**最为重要，避免漏服或随意更改剂量。同时要继续监测血压变化，记录数据并及时反馈给医生，以便评估治疗效果和调整方案。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYY0A228RAB2Q65D5SX3','药物相关','服药时机咨询','{"回答标签": ["专业严谨", "未直接给出唯一答案"], "场景标签": ["服药时机咨询"], "患者标签": ["45岁", "高脂血症", "规律服药", "血压波动小"], "补充标签": [], "患者发言标签": ["咨询本人", "疑问语气"]}',NULL,NULL,NULL,NULL,'2026-02-10 17:39:22.17348+08','2026-02-10 17:42:52.560673+08','场景描述结合患者年龄、病史、用药情况、血压情况及当前咨询问题整合；患者提问保留原意整理为通顺的问题；回复案例将其中的药物说明相关JSON结构整体脱敏为[药物说明JSON]，其余内容保留；根据患者咨询药物服用时间的内容确定场景与子场景。',0.9500,'fb1c2bb82be297fbade3fc45afc733db','success',NULL,'20260210173922'),
	 ('01KH3EPXN2KTQYMFF5B3TQTNWH','40岁冠心病患者，规律服用[盐酸贝尼地平片]，本次测量血压为147/99mmHg，属于轻度偏高，心率71次/分，为正常范围；该患者7天血压趋势无显著变化，曾有过心慌、胸闷、早搏、心动过缓病史，此次上传血压及心率数据。','记录本次血压147/99mmHg、心率71次/分','你能主动监测并告诉我血压情况，这个习惯非常棒！已经帮你记录了这次的血压数据。为了更全面地了解你的血压控制情况，我们先来看一下近期的血压趋势。

trendStartDay=[日期], trendEndDay=[日期]
content=

从趋势来看，你近一周的血压整体控制在目标范围内（135/85mmHg以下），达标率达到85.7%，这个结果很不错。不过今天测量的血压147/99mmHg，已经超过了目标值，属于**血压偏高**的情况。心率71次/分在正常范围内。结合你有冠心病病史并接受过静脉溶栓治疗，血压的突然升高需要引起重视。血压偏高时需要特别留意身体反应，最近是否还有其他症状可以通过下面的工具告诉我们。

[症状收集工具JSON]
content=

考虑到你目前的血压情况，建议尽快到医院复诊，让医生评估是否需要调整治疗方案。了解医生的门诊排班信息可以帮助你更好地规划就诊时间。

scheduleStartDay=[日期], scheduleEndDay=[日期]
content=

持续学习高血压和冠心病管理知识对长期健康非常重要，这里有一些专业的科普文章可以帮助你更深入了解相关注意事项。

