content=

记得任何药物调整都需要医生根据你的具体情况来决定，不要自行更改剂量或停药。如果后续血压出现明显波动或有其他不适，建议及时复诊。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYRR2M1JEF4XRTRRDAMH','记录血压','自测血压结果告知与观察','{"回答标签": ["语气友好", "健康指导", "关注症状变化"], "场景标签": ["血压监测", "脉搏监测"], "患者标签": ["45岁", "高脂血症", "规律服药", "晨间血压偏高", "脉搏偏快"], "补充标签": [], "患者发言标签": ["告知情况", "语气礼貌", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-10 17:39:22.17348+08','2026-02-10 17:51:50.761486+08','场景描述结合患者年龄、病史、用药情况、血压趋势及本次自测的血压、脉搏数据，按规则判断血压达标、脉搏偏快；患者提问将原发言的数值明确为血压和脉搏指标；回复案例对具体日期进行脱敏处理；依据当前患者发言的核心内容判断场景为记录血压。',0.9500,'8d290ad937b122da5a9a5157e20a3fed','success',NULL,'20260210173922'),
	 ('01KH3EPXK784HZVH19FM6FP8P7','50岁糖尿病患者，规律服用[二甲双胍]，睡眠良好，7天血压趋势下降，此次告知[医生]家属[姓名]的查血单子已出，请求查看','刁大夫你好，你帮我看看张建侠的查血单子，结果出来了','我注意到你提到了查血单子的结果，但目前我没有看到具体的检查报告内容。血液检查结果需要结合具体的项目数值（如血糖、血脂、肝肾功能等）和参考范围来分析，这样才能给出有针对性的解读和建议。建议你将检查报告清晰地展示出来，或者提供具体的检查项目和数值，我会帮你进行初步分析。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYRY3P0H5MPNQK8MVJPR','诊疗相关','咨询检查结果解读','{"回答标签": ["引导补充信息"], "场景标签": ["检查结果咨询"], "患者标签": ["50岁", "糖尿病", "规律服药", "7天血压趋势下降"], "补充标签": [], "患者发言标签": ["咨询家属情况", "语气礼貌"]}',NULL,NULL,NULL,NULL,'2026-02-10 17:39:22.17348+08','2026-02-10 17:51:56.970212+08','场景描述结合上下文患者的年龄、疾病、用药、血压情况及当前发言整理，对敏感信息进行脱敏；患者提问对原发言进行语句通顺化调整；回复案例直接使用提供内容，无需脱敏；根据患者请求查看查血结果的内容确定场景与子场景',0.9000,'44a030003ff94af1218d59538dc4346e','success',NULL,'20260210173922');
INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH3EPXK8Z9JHESGQABWPJQ6H','55岁脑梗患者，规律服用[拜阿斯匹灵]，日常不抽烟、坚持运动，血压记录达标，当前咨询复查的预约方式','该复查了，怎么预约？','目前我无法直接帮你预约复查，建议你通过[医院]官方渠道（如官网、公众号或官方电话）进行预约。为了让你更方便地安排就诊时间，可以先查看门诊排班表，了解医生的出诊信息，这样能帮助你选择合适的就诊日期。需要注意的是，复查时医生可能会根据你的具体情况调整治疗方案或开具相关检查，建议提前准备好近期的血压监测记录和用药情况，以便医生更全面地评估你的健康状况。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYRZN47XS94QSN4V19PC','院内资源/政策咨询','复查预约咨询','{"回答标签": ["未直接解决预约", "给出建议"], "场景标签": ["复查预约"], "患者标签": ["55岁", "脑梗病史", "规律服药", "血压达标", "无吸烟习惯", "坚持运动"], "补充标签": [], "患者发言标签": ["咨询本人", "语气平实"]}',NULL,NULL,NULL,NULL,'2026-02-10 17:39:22.17348+08','2026-02-10 17:52:03.84196+08','场景描述结合患者上下文信息及当前提问整理；患者提问是对原发言的规范表述；回复案例按脱敏规则对医院信息进行脱敏处理',0.9500,'6fc1ef20ae606593f0d0ba68823fd03f','success',NULL,'20260210173922'),
	 ('01KH3EPXKBRZEN2GRH5KPP3YBB','55岁脑梗患者，存在视力模糊症状，有7天夜间血压偏高趋势，服药不规律，现咨询耳鸣和脑梗是否为同一回事。','耳鸣和脑梗是一回事吗？','耳鸣和脑梗并不是一回事，但两者之间可能存在一定的关联。脑梗是脑血管堵塞导致的脑组织缺血性损伤，而耳鸣是在没有外界声源时，耳内或颅内出现声音感觉，可能由多种原因引起。
脑梗有时可能会引起耳鸣症状，特别是当脑梗死影响到与听觉相关的脑血管或脑组织时。此外，高血压、动脉硬化等脑梗的危险因素，同时也是耳鸣的常见诱因。这些因素可能导致内耳血液循环不畅或神经损伤，从而引起耳鸣。
不过，耳鸣更多时候是耳部本身疾病（如中耳炎、内耳病变等）或其他全身疾病（如贫血、甲状腺功能异常等）的表现。所以出现耳鸣不一定意味着发生了脑梗，但对于有脑梗病史的人来说，需要关注耳鸣是否伴随其他症状，如头晕、肢体麻木无力、言语不清等，这些可能提示脑血管问题。
如果耳鸣是突然出现的，或者伴有上述提到的其他症状，建议及时就医检查，以明确原因并进行针对性处理。平时也需要继续做好血压管理、规律服药和健康生活方式，这对预防脑梗复发和缓解耳鸣都有帮助。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYS3A5GQCSEE6HYZSDYS','诊疗相关','疾病关联咨询','{"回答标签": ["专业解答", "就医建议"], "场景标签": ["疾病关联咨询"], "患者标签": ["55岁", "脑梗病史", "视力模糊", "夜间血压偏高", "服药不规律"], "补充标签": [], "患者发言标签": ["咨询本人", "疑问语气"]}',NULL,NULL,NULL,NULL,'2026-02-10 17:39:22.17348+08','2026-02-10 17:52:21.030034+08','场景描述结合上下文患者年龄、病史、症状、血压情况、服药状态及当前提问生成；患者提问对原表述进行了简洁化整理；回复案例直接使用给定内容，未做非脱敏修改；无回复规则内容。',0.9500,'0f7f7bd0979bfe1205f69a70151d1571','success',NULL,'20260210173922'),
	 ('01KH3EPXKB0CV3YQ465N00HDVP','55岁脑梗患者，规律服用[拜阿斯匹灵]，近期7天血压趋势上升，日常少吃盐、睡眠良好，咨询谢医生次日是否出诊。','谢医生明天有上班吗？','我无法直接查看医生的实时排班情况。你可以通过[医院]官方渠道（如官网、公众号或官方电话）查询谢医生的出诊时间并进行预约。如果需要开药或调整治疗方案，建议在就诊时携带相关病历资料，以便医生更好地了解情况。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPYS4FCWYM2V920KDG0KE','院内资源/政策咨询','医生出诊时间咨询','{"回答标签": ["未直接回答患者问题", "引导官方渠道查询"], "场景标签": ["出诊时间咨询"], "患者标签": ["55岁", "脑梗病史", "规律服药", "血压趋势上升"], "补充标签": [], "患者发言标签": ["咨询他人", "语气平和"]}',NULL,NULL,NULL,NULL,'2026-02-10 17:39:22.17348+08','2026-02-10 17:52:16.243035+08','场景描述结合患者年龄、疾病、用药、血压情况及当前提问信息整理；患者提问保留原问题原意；回复案例对提及的医院进行脱敏处理；根据患者提问内容判断所属场景和子场景。',0.9500,'bfd0225f87475f436411aaedd132c269','success',NULL,'20260210173922'),
	 ('01KH3EPXK9ZGNE989R1X1RCZC9','55岁脑梗患者，有头昏头晕症状，此次告知高压150mmHg、低压92mmHg、心率75次/分，血压轻度偏高，心率正常。','记录我的血压：高压150mmHg、低压92mmHg，心率75次/分','你能主动监测并记录血压，这个习惯非常棒！已经帮你保存了这次的血压记录。从数据来看，这次测量的血压是150/92mmHg，心率75次/分，心率在正常范围内，但血压没有达到你的目标值（135/85mmHg）。单次血压升高可能受多种因素影响，比如测量前是否有活动、情绪波动、休息是否充分等。
血压偏高时需要特别留意身体反应，看看最近是否有什么不舒服的症状。

[症状收集选项JSON]

