articleId=2665, articleTitle=血压稳定就可以停药吗？, articleUrl=null, articleImage=https://itg-tezign-files.tezign.com/t256/MTc2MDQyMTU3MjAyNGRhOWE3YjQ3LTYyZDgtNGFhZi04YjM2.png?Expires=1767283199&OSSAccessKeyId=LTAI5tDubGKMRMroG8MuTLZo&Signature=D%2BLve9VPXAb%2BngZryuO8LuRdugU%3D&response-content-disposition=inline&image_process=resize,l_300
content=

请记住，如果出现**头晕加重、意识模糊、胸痛**等症状，一定要及时就医。继续坚持监测血压，定期记录，这对于血压的长期稳定控制非常重要。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ2QVBF2HZESSDS7WK9X','诊疗相关','咨询调整用药','{"回答标签": ["引导就医", "推荐文章", "记录血压"], "场景标签": ["血压咨询", "用药咨询"], "患者标签": ["55岁", "高血压", "规律服药", "高压偏低"], "补充标签": ["血压预警"], "患者发言标签": ["咨询本人", "疑问语气"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:28:44.40521+08','场景描述结合患者年龄、高血压病史、用药情况、当前血压数据及预警情况、历史记录等信息整合；患者提问根据当前患者发言改写为完整清晰的问题；回复案例对其中具体日期进行脱敏处理；根据患者咨询是否继续服药判断为咨询调整用药的诊疗相关场景。',0.9500,'8126d82b413bd3d370e31a4b91df778e','success',NULL,'20260211172011');
INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH600GMVEE5M5QEBNAASCTYH','50岁糖尿病患者，规律服用[二甲双胍]，有血压监测记录，14天血压趋势无显著变化，日常保持少吃盐、心情放松的习惯，此前有多次被引导回院复诊、阅读科普文章的记录，此次因看到网上说法，对自己一直早上服用苯磺酸氨氯地平片的服药时间产生疑问，前来咨询。','请问服用苯磺酸氨氯地平片到底应该早上吃还是晚上吃？最近看到网上有的医生说治疗高血压的药应该晚上吃，因为早上是血压第一个高峰而且即使吃药了还有个半衰期，影响治疗效果。我以前一直都是早上吃，不知是否正确？','苯磺酸氨氯地平片是一种长效降压药，半衰期长达35-50小时，通常每日服用一次即可维持24小时血压稳定。关于服药时间，目前并没有统一的最佳时间，需要根据个人血压波动规律来调整。
一般来说，早晨服药可以覆盖白天的血压高峰，而晚上服药可能更适合夜间血压偏高或晨起血压明显升高的患者。你可以通过监测全天血压变化，特别是早晚血压，了解自己的血压波动特点，再和医生沟通调整服药时间。
这里有苯磺酸氨氯地平片的药品说明书，你可以查看了解使用规范，不过用药存在个体差异，一定要以医嘱为准。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ83VPY4WM3QPK4JV8AP','药物相关','服药时机咨询','{"回答标签": ["专业解答", "引导就医沟通"], "场景标签": ["服药时机咨询", "高血压用药"], "患者标签": ["50岁", "糖尿病", "规律服药", "血压趋势稳定"], "补充标签": [], "患者发言标签": ["咨询本人", "疑问语气"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:33:17.222813+08','场景描述根据上下文患者的年龄、疾病、用药、血压情况、历史行为及当前提问整理；患者提问根据当前发言保留原意改写为完整清晰的问题；回复案例按原文保留未修改；回复规则无内容故为空。',0.9500,'8d1bb2a0e41386e34df3dae75d6f38af','success',NULL,'20260211172011'),
	 ('01KH600GJDJDB6TZJF781STNQE','58岁患有高脂血、糖尿病的患者，存在肌肉不适症状，曾被引导回院复诊，此次刚做完核磁共振，咨询小脑萎缩的应对办法，提及父亲因该病去世。','医生！刚做完核磁共振，查出小脑萎缩怎么办？我父亲是因这种病去世的。','这种情况确实会让人感到担忧。小脑萎缩有多种可能的原因，包括遗传性、变性性、缺血缺氧性等，而你提到父亲有相关病史，更需要引起重视。不过目前仅凭核磁共振结果还不能确定具体病因和进展情况，建议尽快到神经内科就诊，进行全面的神经系统评估和相关检查，以明确诊断和制定合适的管理方案。我是心血管内科医生的数字分身，主要专注于高血压等心血管疾病的慢病管理。如果你在血压监测、用药管理或心血管健康方面有任何疑问，我很乐意为你提供专业的建议和帮助。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ29VF2AE93R8BFT82Y7','咨询其它科室问题','神经系统疾病咨询','{"回答标签": ["专业引导", "明确告知诊疗范围"], "场景标签": ["小脑萎缩咨询", "核磁共振后咨询"], "患者标签": ["58岁", "高脂血", "糖尿病", "肌肉不适", "有家族病史"], "补充标签": [], "患者发言标签": ["语气急切", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:28:04.365216+08','场景描述结合上下文患者的年龄、基础疾病、症状、历史引导动作及当前患者发言的信息整合；患者提问根据当前患者发言整理为完整清晰的问题；回复案例直接使用给定内容，未做非敏感信息修改；根据患者咨询的小脑萎缩属于神经内科范畴，判定为咨询其它科室问题场景。',0.9500,'343963e6eaec01c3ead0812fdaab1d01','success',NULL,'20260211172011'),
	 ('01KH600GJGSD14Z9WG6ACAZ01T','48岁冠心病患者，有胸闷症状，存在不规律服药情况，7天血压趋势上升，此前有血压波动异常的情况，曾被引导回院复诊、记录症状，此次告知最新血压为121/61mmHg，脉搏68次/分，当前血压达标，脉搏正常。','记录血压121/61mmHg，脉搏68次/分','你能主动监测并告诉我血压情况，这个习惯非常棒！已经帮你记录了今天的血压数据。你的收缩压121mmHg，舒张压61mmHg，脉搏68次/分，根据你的个人目标血压（135/85mmHg），当前血压控制在目标范围内，属于正常水平，脉搏也在正常范围内。从近期趋势来看，你近7天的血压整体呈现小幅波动后逐渐趋于稳定的状态，达标率约85.7%，控制情况良好。不过需要注意的是，你今天早些时候出现了血压从140/78mmHg到90/59mmHg的明显波动，虽然现在恢复正常，但这种不稳定性对于有冠心病病史并接受过溶栓治疗的情况来说仍需要密切关注。考虑到你之前提到计划在[日期]进行复检，结合近期的血压波动情况，建议你在复检前继续做好血压监测，记录每天的血压变化情况。你可以查看医生近一个月的门诊排班信息，以便根据实际情况调整就诊安排。在日常生活中，建议你继续保持规律服药，注意低盐饮食，避免情绪波动和过度劳累。关于高血压合并冠心病患者的血压管理和日常注意事项，这里有相关的科普文章可以帮助你深入了解。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ2ER2VT1ZCEDKK2CX8T','记录血压','记录血压及脉搏数据','{"回答标签": ["引导监测", "建议规律服药", "推荐科普文章"], "场景标签": ["血压记录", "脉搏记录"], "患者标签": ["48岁", "冠心病", "胸闷", "不规律服药", "血压曾有异常波动"], "补充标签": ["血压达标", "脉搏正常"], "患者发言标签": ["陈述记录", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:28:20.407307+08','场景描述结合患者年龄、病史、症状、服药情况、血压趋势、历史就诊引导及此次血压脉搏数据整合；患者提问将患者的血压脉搏记录需求明确化；回复案例对日期进行脱敏处理，其余保留原文内容；根据患者发言判断场景为记录血压。',0.9500,'46c4b00dd9240a4196ce75e2b1ceeae8','success',NULL,'20260211172011'),
	 ('01KH600GJMD2JPBX51C0PRKWEA','67岁的冠心病、高脂血、脑梗患者，规律服药，存在夜间血压高的7天血压趋势，有胸痛症状，今日测量左手高压154mmHg、右手高压134mmHg，双侧血压差值达20mmHg，需预警尽快回院。','今天测量左手高压154mmHg，右手高压134mmHg，双侧血压差20mmHg，这种情况该怎么办？','你能持续关注血压变化并及时反馈，这种认真态度非常值得肯定！你提到左右手臂血压相差20mmHg，这种情况需要引起重视。一般来说，健康人双侧上臂血压差别达5～10mmHg，若超过10mmHg则属于异常，可能提示血管存在病变，比如主动脉夹层、大动脉炎或动脉粥样硬化等，结合你有冠心病和脑梗病史，更应警惕这种血压差异可能带来的健康风险，建议尽快到[医院]进行进一步检查明确原因。
为了更全面了解你的血压变化规律，我们先来看一下近期的血压趋势图。

从趋势分析来看，你的血压呈现出明显的**夜间升高模式**，白天血压多数时候能够达标，但到了晚上血压就会升高。目前你左右手臂血压差异较大，同时夜间血压控制不佳，这两种情况都需要特别关注。血压异常时需要特别留意身体反应，最近是否还有头晕、肢体麻木等症状，可以通过工具告诉我。
关于血压测量差异和夜间高血压的管理，及时复诊调整治疗方案非常重要。你可以查看医生近期的门诊排班情况，提前安排就诊时间。

这里有一些关于血压测量规范和高血压管理的专业科普文章，你可以点击查看，帮助你更深入地了解相关知识。

记住，对于有冠心病和脑梗病史的人来说，血压的稳定控制至关重要。如果出现**胸痛、剧烈头痛、肢体活动障碍等症状**，请立即就医。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ2PTV385JPWKWXWSGXY','诊疗相关','血压异常咨询','{"回答标签": ["预警提示", "引导回院", "推荐文章"], "场景标签": ["血压异常", "双侧血压差值大"], "患者标签": ["67岁", "冠心病", "高脂血", "脑梗", "胸痛", "夜间血压高", "规律服药"], "补充标签": ["需尽快就诊"], "患者发言标签": ["咨询本人", "陈述异常指标"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:28:34.388759+08','场景描述结合患者年龄、病史、症状、血压趋势及本次血压测量情况提取；患者提问根据当前患者发言补充完整疑问；回复案例按脱敏规则对医院名称脱敏；结合患者当前血压异常咨询的情况确定场景与子场景。',0.9500,'a91b0492056d8a078c3144482dd40e0e','success',NULL,'20260211172011'),
	 ('01KH600GJNYF5X7K2PHW7XH8BS','55岁高血压患者，规律服用[苯磺酸氨氯地平片]，14天血压趋势无显著变化，曾因更换降压药后血压偏低咨询医生。此次告知医生今日在[药店]测量的血压为100/60，该血压值属于高压偏低（需预警，尽快回院）。','您好医生，今天在[药店]量的血压，高压100、低压60，这个老款量血压的，拍不了照','你能主动监测并告诉我血压情况，这个习惯非常棒！你今天在[药店]测量的血压是100/60，从数值上看属于正常范围。不过结合你之前的情况，这个血压比你近期稳定的血压水平明显偏低，需要引起重视。
为了更全面地了解你近期的血压控制趋势，我们可以通过工具查看你近段时间的血压变化情况。

从趋势图可以看出，你之前的血压一直稳定在130/78左右，控制得很好，而今天突然降到100/60，这种明显的血压波动可能与你刚换用新的高血压药物有关。你之前提到吃新的高血压药才五天，药物效果可能还在调整阶段。血压偏低时，需要特别留意身体反应，比如是否有头晕、乏力、眼前发黑等不适症状。
考虑到你目前的血压情况，建议尽快联系医生，详细说明血压变化和用药情况，由医生评估是否需要调整药物剂量或方案。如果你需要近期复诊，可以通过下面的工具查看医生近一个月的门诊排班信息，以便提前安排时间。

在医生评估前，不要自行调整药物剂量或停药，同时要继续密切监测血压变化，尤其是在早晨起床后和晚上睡前等关键时间点。关于高血压药物治疗期间的血压管理，还有很多需要注意的细节，你可以点击查看相关的科普文章，帮助你更好地了解和应对。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ2T5KHCGDJ2R7RC35V5','诊疗相关','血压异常咨询','{"回答标签": ["引导回院", "建议监测", "推荐文章"], "场景标签": ["血压监测", "血压异常"], "患者标签": ["55岁", "高血压", "规律服药", "高压偏低"], "补充标签": [], "患者发言标签": ["告知血压数据", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:28:47.653049+08','场景描述结合患者年龄、病史、用药情况、血压数据及历史咨询信息生成，对药店进行脱敏；患者提问对药店进行脱敏；回复案例对药店进行脱敏，其余内容保留原文结构和信息；根据患者血压异常咨询的情况确定场景和子场景；标签从场景、患者情况、发言特点等方面提取。',0.9500,'7fe9652d2fbd16fdab868a1210d988ca','success',NULL,'20260211172011'),
	 ('01KH600GMT4NZRZ72TMT70XR76','55岁脑梗患者，规律服用[拜阿斯匹灵]，日常少吃盐、睡眠良好，14天血压趋势上升，曾多次被引导回院复诊、阅读科普文章，现咨询耳鸣和脑梗是否为同一回事。','你好，耳鸣和脑梗是一回事吗？','耳鸣和脑梗不是一回事，但脑梗可能会引起耳鸣症状，需要关注两者之间的关联。
### 1. 两者的本质区别
- **耳鸣**：是一种症状，表现为在没有外界声源的情况下，耳内或颅内出现异常声音感觉，可能是嗡嗡声、鸣声、嘶嘶声等。
- **脑梗**：是一种疾病，指因脑部血液供应障碍，缺血、缺氧所导致的局限性脑组织的缺血性坏死或软化。
### 2. 脑梗与耳鸣的关联
脑梗可能会影响听觉相关的神经通路或中枢，从而引起耳鸣症状。但耳鸣的原因很多，不一定都是脑梗引起的，也可能与耳部疾病、高血压、颈椎病、精神压力等多种因素有关。
### 3. 建议
- **关注症状变化**：如果耳鸣持续存在或加重，同时伴有头晕、头痛、肢体麻木、言语不清等其他不适症状，应及时就医，进行相关检查，明确病因。
- **控制基础疾病**：你有脑梗病史，应遵医嘱控制好血压、血糖、血脂等基础指标，定期复查，预防脑梗复发。
- **避免自行判断**：不要自行判断耳鸣的原因或随意用药，应在医生指导下进行诊断和治疗。
如果耳鸣症状明显或伴有其他不适，建议尽快到医院就诊，由医生进行专业评估和处理。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ82ZJV9M3YV7VVV3JZC','诊疗相关','疾病关联咨询','{"回答标签": ["专业解答", "给出建议"], "场景标签": ["疾病关联咨询"], "患者标签": ["55岁", "脑梗病史", "规律服药", "血压趋势上升"], "补充标签": [], "患者发言标签": ["咨询本人", "疑问语气"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:33:17.755738+08','场景描述结合上下文的患者年龄、病史、用药、血压情况及当前提问整理；患者提问修正原句语序使表达更通顺；回复案例按原文保留并仅对敏感信息脱敏；根据患者咨询疾病关联的内容确定场景与子场景。',0.9500,'376966cfad8458b2b1465cf00c8cfe51','success',NULL,'20260211172011'),
	 ('01KH600GN5YN6EBT94C16F169T','35岁高血压患者，有头昏头晕症状，28天血压趋势上升，无服药数据，此前有过科普文章阅读、引导回院复诊的记录，现咨询医生排班情况。','谢医生明天有上班吗','作为医生的数字分身，当前可以为你提供高血压慢病健康管理及科学指导，你咨询的此类问题暂无法回复，建议你通过医院的官方渠道（如官网、公众号或官方电话）直接咨询。
