INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH600GMCHAYVC1J9EAXNCFFZ','69岁患者，患有高血压、糖尿病、冠心病、脑梗，存在头昏症状，有不规律服药情况，7天血压趋势晨间高，此次咨询手中药物的服用剂量，询问是否吃一片。','你好，我想问一下这个药怎么吃，是吃一片吗？','我看到你询问的是枸橼酸莫沙必利片的服用方法。这个药主要用于改善胃肠动力，适合有消化不良、胃灼热、恶心等症状的患者。
我注意到这个药还不在你的用药方案中，建议添加进去，方便后续管理。这里有药品说明书的详细信息，你可以查看了解使用规范，不过一定要以医嘱为准。

[药品信息JSON]

鉴于你有多种慢性病史，任何用药调整都需要医生根据你的具体情况来决定，**请务必遵医嘱用药**，不要自行调整或停药。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ7FPD84S1G9A40W7G4R','药物相关','用药剂量咨询','{"回答标签": ["提醒遵医嘱", "提及药品信息"], "场景标签": ["用药咨询", "剂量询问"], "患者标签": ["69岁", "高血压", "糖尿病", "冠心病", "脑梗", "头昏", "不规律服药"], "补充标签": [], "患者发言标签": ["语气平和", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:32:30.719138+08','场景描述结合上下文里的患者年龄、病史、症状、用药情况以及当前提问信息整理；患者提问保留原意优化表述；回复案例将原案例中的药品信息段落替换为[药品信息JSON]进行脱敏；根据患者提问内容确定场景与子场景；所有敏感信息已按规则处理。',0.9500,'01c61d04cd1ba6dff8d6c6053dc9180b','success',NULL,'20260211172011'),
	 ('01KH600GMP4XXFCCZ025QCTV4Q','40岁冠心病患者，规律服用[盐酸贝尼地平片]，14天血压趋势无显著变化，曾因心慌、胸闷、早搏感被引导回院复诊，今日告知右腿膝关节内侧出现血淤青点。','今发现右腿膝关节内侧有血淤青点，该怎么办？','膝关节内侧出现淤青点可能与局部轻微外伤、皮下毛细血管破裂等因素有关，对于有冠心病病史的人来说，也需要关注是否存在其他潜在问题。以下是需要注意的事项：
### 观察要点
- **淤青范围变化**：留意淤青是否扩大、颜色是否加深，或身体其他部位是否出现新的淤青。
- **伴随症状**：注意是否有局部疼痛、肿胀、活动受限，或全身症状如牙龈出血、鼻出血、头晕乏力等。
### 建议
- **避免局部刺激**：暂时避免对淤青部位进行按压、揉搓或热敷，以免加重皮下出血。
- **及时就医评估**：鉴于你有冠心病病史，建议尽快到[医院]就诊，通过检查明确淤青原因。医生可能会进行血常规、凝血功能等检查，排除潜在的血液系统问题或其他健康风险。
请不要自行判断或处理，务必由专业医生进行评估和指导。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ7T9H8WB70GN630WKRA','诊疗相关','症状咨询','{"回答标签": ["就医引导", "专业建议"], "场景标签": ["症状咨询", "冠心病"], "患者标签": ["40岁", "冠心病", "规律服药", "血压趋势稳定"], "补充标签": ["皮下淤青"], "患者发言标签": ["咨询本人症状", "陈述症状"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:32:50.378474+08','场景描述结合上下文患者的年龄、病史、用药情况、血压趋势、历史就医引导信息及当前症状整理；患者提问根据患者当前发言补充明确诉求；回复案例对其中的医院信息进行脱敏处理；场景及子场景根据患者咨询身体症状的内容判定。',0.9500,'bf23e4296e80d25eb69daceaa0a38b66','success',NULL,'20260211172011'),
	 ('01KH600GKWARHWJ7NCGQ7QR5RX','60岁的高血压、冠心病患者，规律服用苯磺酸氨氯地平片、盐酸贝尼地平片，7天血压趋势无显著变化。此次告知[日期]的化验结果显示总胆红素22.9、尿素8.8，总胆固醇5.88和低密度脂蛋白固醇3.80均超出正常范围0.6个单位，咨询能否增加一粒血脂康的服用量。','我前两天的化验结果显示总胆红素22.9，尿素8.8，总胆固醇5.88和低密度脂蛋白固醇3.80都高了0.6个单位，请问能否多吃一粒血脂康（原来吃两粒）？','根据你提供的信息，总胆固醇和低密度脂蛋白胆固醇略高于正常范围，总胆红素和尿素也有轻度升高。这些指标的异常可能与饮食、生活习惯或代谢状态有关。
### 重要提醒
不建议自行调整用药剂量或频次。血脂康属于中成药，其使用需要根据你的具体健康状况、血脂水平、肝肾功能等综合评估。自行调整用药可能会影响治疗效果或增加不良反应风险。
### 行动建议
- **尽快就医**：建议携带化验单到医院就诊，由医生评估血脂异常的原因和程度，结合你的冠心病病史，制定个体化的治疗方案。
- **生活方式调整**：
  - 保持低脂饮食，减少动物内脏、油炸食品等高脂肪食物的摄入。
  - 增加蔬菜、水果、全谷物等富含膳食纤维的食物。
  - 规律运动，控制体重。
- **定期监测**：遵医嘱定期复查血脂、肝功能等指标，监测治疗效果和药物安全性。
用药方案的调整需要医生根据你的具体情况综合判断，请务必在医生指导下进行。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ6NSSG8KGSMC2F25PPP','药物相关','咨询调整用药剂量','{"回答标签": ["给出行动建议", "提醒勿自行调整用药"], "场景标签": ["用药调整咨询", "血脂异常"], "患者标签": ["60岁", "高血压", "冠心病", "规律服药", "血脂指标异常"], "补充标签": [], "患者发言标签": ["咨询本人", "语气礼貌"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:31:42.487948+08','场景描述结合患者年龄、病史、用药情况、血压趋势及本次的化验异常情况和诉求整合；患者提问根据当前发言改写为完整清晰的问题；回复案例仅对敏感信息进行脱敏处理，保留原内容结构和非敏感信息；根据患者诉求判断场景为药物相关下的咨询调整用药剂量。',0.9500,'ab857127712ecd2d24f7954625e4482d','success',NULL,'20260211172011'),
	 ('01KH600GM0DTYXE9WVTR8GCX2Z','70岁的患者患有高血压、高脂血、冠心病，有胸痛症状，曾出现过血压波动较大的情况，刚在[医院]复诊后，咨询医生提及的姓名不对的问题。','我刚去复诊了，[医生]说我的姓名不对，这是怎么回事？','作为医生的数字分身，我主要为你提供高血压慢病健康管理及科学指导，你咨询的此类问题暂无法回复。建议你通过医院的官方渠道（如官网、公众号或官方电话）咨询，或在复诊时向医生详细确认相关信息。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ70NQTWX3RCWGS5FSJF','院内资源/政策咨询','就诊信息疑问咨询','{"回答标签": ["未直接回答患者问题"], "场景标签": ["就诊信息疑问"], "患者标签": ["70岁", "高血压", "高脂血", "冠心病", "有胸痛症状", "血压波动较大"], "补充标签": [], "患者发言标签": ["咨询本人", "疑问语气"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:31:56.50674+08','场景描述结合患者年龄、病史、症状、血压情况及本次复诊后的疑问整理，同时对敏感信息进行脱敏；患者提问保留原意并对医生姓名脱敏；回复案例按要求保留原内容未做修改；根据患者咨询就诊信息问题确定场景及子场景。',0.9500,'cfa2d3591c8fdd88e968a1f9a8017a24','success',NULL,'20260211172011'),
	 ('01KH600GM6TNCNC66BMZCYGZ6S','72岁患者，患有高血压、糖尿病、脑梗、高脂血，存在视力模糊症状，有不规律服药情况，7天血压趋势为夜间高。此次在[药店]用老款血压计测得血压为100/60，高压偏低（需预警，尽快回院），告知医生相关情况。','医生，我今天在[药店]用老款血压计量的血压是高压100、低压60，这个情况怎么看？','你能主动监测并告诉我，这个习惯非常棒！我已经帮你记录了这次的血压数据（100/60）。
### 血压点评
从你提供的血压数据来看，高压和低压都处于正常范围。不过因为你有高血压病史，单次的血压测量数据可能会受到很多因素的影响，比如测量时的状态、是否刚运动过等，所以建议你继续坚持规律地监测血压，这样能更全面地了解自己的血压变化情况。
### 行动建议
建议你继续坚持规律地监测血压，同时关注自己的身体状况，如有任何不适，及时就医。另外，考虑到你还患有糖尿病、高脂血症和脑梗等疾病，除了监测血压，也别忘记关注这些疾病相关的指标和症状哦。如果你想了解更多关于高血压、糖尿病等慢病管理的知识，这里有一些专业的科普文章可以供你参考：

[科普文章列表JSON]',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ77QAVE0VTFCNQXG2T9','记录血压','血压结果告知','{"回答标签": ["血压点评", "健康建议", "推荐科普文章"], "场景标签": ["血压记录", "高压偏低预警"], "患者标签": ["72岁", "高血压", "糖尿病", "脑梗", "高脂血", "视力模糊", "不规律服药", "夜间血压高"], "补充标签": ["慢病管理"], "患者发言标签": ["告知血压数据", "咨询本人情况"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:32:13.15722+08','场景描述结合患者年龄、病史、症状、用药、血压趋势及本次血压情况，按规则判定高压偏低并预警；患者提问根据患者发言改写为明确的咨询问题；回复案例对敏感的文章链接信息按规则替换为占位符；根据患者发言内容判定场景为记录血压下的血压结果告知。',0.9500,'33742b5fa530fb864dd911423f2cb2c0','success',NULL,'20260211172011'),
	 ('01KH600GMB6V2BBQ7GJGRKS898','71岁患者，患有高血压、冠心病、脑梗、高脂血，规律服药，有胸闷症状，此前有科普文章阅读史，目前咨询门冬胰岛素注射后针头有滴状残留的问题','杨医生您好，我现在打胰岛素，甘精胰岛素注射情况正常，门冬胰岛素会出现打完后针头还有点滴状残留，这该怎么处理？','门冬胰岛素注射后针头有滴状残留，可能有以下几种原因及相应的处理建议：
- **注射后未及时拔针**：如果在注射完后没有立即拔针，药液可能会由于重力作用或针管内的压力变化而流出，形成残留。建议在注射完毕后，停留10 - 15秒再拔针，这样可以让药液充分进入体内，减少残留。
- **针头或注射笔的问题**：
    - 针头可能有堵塞、弯曲等情况，影响药液的正常注射和残留情况。需要检查针头是否完好，如有问题及时更换新的针头。
    - 注射笔的推杆可能没有推到底，导致部分药液残留在针管内。注射时要确保推杆完全推到底，将药液全部注入。
- **注射部位和角度问题**：如果注射部位过浅或者注射角度不当，可能会影响药液的吸收和残留情况。要按照正确的方法进行注射，一般门冬胰岛素的注射部位可选择腹部、大腿外侧、上臂外侧和臀部外上侧，注射角度一般为90°（较瘦的人或儿童可选择45°）。
如果调整上述操作后，仍然存在明显的药液残留，或者还伴有注射部位疼痛、红肿等不适，建议咨询内分泌科医生或药师，以确定是否存在注射装置的问题或其他异常情况。
另外，如果你有任何需要记录的数据（如血压、服药信息等）、健康疑问，都可以随时告诉我，我会随时为你提供专业的建议和帮助。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ7ETJWW6M5H0RMDFQWX','药物相关','胰岛素注射问题咨询','{"回答标签": ["专业指导", "给出解决方案"], "场景标签": ["胰岛素注射咨询"], "患者标签": ["71岁", "高血压", "冠心病", "脑梗", "高脂血", "胸闷", "规律服药"], "补充标签": [], "患者发言标签": ["咨询本人", "语气礼貌"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:32:28.871498+08','场景描述根据上下文的患者年龄、疾病、症状、用药、历史行为及当前咨询问题整合；患者提问将原发言补充为完整清晰的问题；回复案例按要求保留原内容未改写；根据患者咨询胰岛素注射残留问题确定场景和子场景',0.9500,'ad78d6d8768cb6448f1f3ffb3155063c','success',NULL,'20260211172011'),
	 ('01KH600GMFPW8Z5X13DM7TAYMY','35岁高血压患者，规律服用[苯磺酸氨氯地平片]，存在夜尿增多症状，14天血压趋势晨间高，有过科普文章阅读、引导回院复诊的历史行为。此次患者称在[医院]复诊时，[医生]告知其姓名不对，前来咨询原因。','我刚去复诊，[医生]说我的姓名不对，这是怎么回事？','作为医生的数字分身，当前可以为你提供高血压慢病健康管理及科学指导，你咨询的此类问题暂无法回复，建议你通过[医院]的官方渠道（如官网、公众号或官方电话）直接咨询，以便获取更准确的信息。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZ7KDPX0BV4F8MA108GA','院内资源/政策咨询','就诊信息问题咨询','{"回答标签": ["未直接回答患者问题"], "场景标签": ["就诊信息疑问"], "患者标签": ["35岁", "高血压", "夜尿增多", "规律服药", "晨间血压高"], "补充标签": [], "患者发言标签": ["咨询本人", "疑问语气"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-11 17:32:36.777244+08','场景描述结合患者历史病情信息、当前发言内容整理，对敏感信息进行脱敏；患者提问将当前发言改写为清晰完整的问题，对敏感信息脱敏；回复案例对原案例中的医院信息进行脱敏；根据患者发言内容判断场景为院内就诊信息相关咨询',0.9500,'cd3458d48912d3444155e8885ec4c1b8','success',NULL,'20260211172011'),
	 ('01KH600GKS9TH74G0WQ4Y4AR3Q','60岁的高血压、冠心病患者，存在胸闷症状，有不规律服药情况，此次告知昨日早中晚三次血压（129/83、130/84、130/82）均为达标状态，心率分别为70、65、64次/分，自述最近心率低，此前有多次引导回院复诊及科普文章阅读的记录。','我昨天的血压：早晨129/83/70，中午130/84/65，晚上130/82/64，最近心率低，想了解相关情况。','你能主动监测并告诉我，这个习惯非常棒！我已经为你保存了这次的血压记录。从你提供的血压数据来看，昨天早晨的血压高压是129mmHg，低压83mmHg，心率70次/分；中午的血压高压130mmHg，低压84mmHg，心率65次/分；晚上的血压高压130mmHg，低压82mmHg，心率64次/分。你的心率相对偏低，可能会引起一些不适症状，比如头晕、乏力等。不过单次的血压和心率测量结果可能会受到很多因素的影响，比如测量时的状态、测量仪器的准确性等。如果可以的话，建议你在不同的时间多测量几次，这样能更全面地了解自己的血压和心率情况。
另外，考虑到你有冠心病和高血压的病史，心率的波动可能会对你的心脏产生一定的影响。你可以关注一下自己是否有胸闷、胸痛、头晕等不适的症状，如果有的话，一定要及时告知医生或者到医院就诊。
为了更好地管理你的血压和心脏健康，你可以查看一下相关的科普文章，了解更多关于冠心病和高血压管理的知识，这对你的健康会很有帮助。
同时，你也可以关注一下医生的门诊排班信息，方便你根据自己的情况安排复诊，及时调整治疗方案。

