INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH600GP1F8531KKYZF0BTHG8','58岁患者，患有高脂血、糖尿病，存在肌肉不适症状，无服药数据，曾阅读科普文章，此次咨询甘油三酯高时阿托伐他汀钙片和血滞通胶囊能否同时服用。','老师下午好，我的甘油三酯高，阿托伐他汀钙片和血滞通胶囊这两种药可以同时吃吗？','这种担忧可以理解，药物的选择和联合使用需要结合你的具体健康状况、合并疾病（如糖尿病、高脂血症）以及药物耐受性等多方面因素综合评估。阿托伐他汀钙片属于他汀类药物，常用于高脂血症的治疗；血滞通胶囊属于中成药，其使用需要结合中医辨证。两者是否适合同时服用，需要由医生根据你的具体情况判断。建议你携带目前的用药记录和检查报告，及时咨询开具处方的医生或药师，由专业人员评估后给出用药建议。切勿自行调整用药方案，以免影响治疗效果或增加不良反应风险。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZB5DBE53PEZXDZA95XS','药物相关','能否一起用','{"回答标签": ["专业建议", "未直接给出联用结论"], "场景标签": ["药物联用咨询", "高脂血症"], "患者标签": ["58岁", "高脂血症", "糖尿病", "肌肉不适"], "补充标签": ["无用药史"], "患者发言标签": ["咨询本人", "语气礼貌"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-12 15:11:40.456437+08','场景描述结合上下文患者年龄、疾病、症状、病史等信息及当前提问整理；患者提问保留原意仅修正药物名称错别字；回复案例按要求保留原文未改写；根据患者提问内容确定场景及子场景；标签从场景、患者情况、发言及回复中提取。',0.9500,'9208000c37c4283c4c592d1099f160c7','success',NULL,'20260211172011'),
	 ('01KH600GNV62XTHF0FRABFE4J9','40岁高血压患者，有头昏头晕症状，无用药，曾有单次血压轻度偏高记录，此前多次被引导回院复诊、阅读科普文章，现咨询谢医生次日的出诊情况。','谢医生明天有上班吗','作为医生的数字分身，当前可以为你提供高血压慢病健康管理及科学指导，你咨询的此类问题暂无法回复，不过我可以为你提供谢医生近一个月的门诊排班信息，方便你了解安排就诊时间和预约。

scheduleStartDay=[日期], scheduleEndDay=[日期]
content=
你可以点击查看排班详情，预约需要去医院官方渠道。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZAQNZVX1AK08CZK2B36','院内资源/政策咨询','医生出诊时间咨询','{"回答标签": ["提供排班信息", "引导官方预约"], "场景标签": ["出诊时间咨询"], "患者标签": ["40岁", "高血压", "头昏头晕", "血压轻度偏高", "无用药"], "补充标签": [], "患者发言标签": ["咨询本人", "语气平和"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-12 15:11:02.562478+08','场景描述结合上下文的患者年龄、疾病、症状、血压情况、历史引导动作及当前提问整理；患者提问直接采用用户原文；回复案例对其中的具体日期进行脱敏处理；根据用户提问判断场景为院内资源/政策咨询下的医生出诊时间咨询。',0.9500,'c7e1524fc67f7c9b0962f6d75ec43256','success',NULL,'20260211172011'),
	 ('01KH600GNZ2A1FVT1VAJJFGCRM','65岁患者，患有高血压、糖尿病、高脂血症，存在夜尿增多症状，7天血压趋势上升，无用药记录。患者此前咨询过用药调整、心脏不适相关问题，本次向AI确认对方是否表达过自己已经复诊过的内容。','您是想说我已经复诊过了是吗？','我之前的回复主要是针对你目前的血压情况和症状给出的健康指导，并没有提及复诊相关的内容。如果你想了解复诊的相关建议，比如复诊的时间、需要携带的资料等，我可以为你提供一些参考信息，你也可以直接咨询你的主管医生以获取更准确的复诊安排。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZAYXH0XY2W8BCAVXJ0H','其它场景','确认对话内容','{"回答标签": ["直接回答"], "场景标签": ["对话确认"], "患者标签": ["65岁", "高血压", "糖尿病", "高脂血症", "夜尿增多", "血压趋势上升"], "补充标签": [], "患者发言标签": ["咨询本人", "疑问语气"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-12 15:11:22.080083+08','场景描述结合上下文患者的年龄、疾病、症状、血压情况及聊天历史改写；患者提问保留原意调整表述更通顺；回复案例按原文脱敏后保留；无回复规则，故省略。',0.9000,'957009e3dbdd58f3cd617a2ea978d8fd','success',NULL,'20260211172011'),
	 ('01KH600GP0A6Q530BA3M7CRP6A','70岁患者，患有高血压、冠心病、脑梗、糖尿病，曾出现胸痛症状，血压曾有中度偏高情况，此次咨询耳鸣和脑梗是否为同一回事。','你好，耳鸣和脑梗是一回事吗？','耳鸣和脑梗**不是一回事**，它们在概念、病因、症状表现和治疗方法等方面都存在明显的差异，具体如下：
- **概念与本质**：
    - **耳鸣**：是一种在没有外界声源刺激的情况下，人耳主观感受到的声音，它是一种症状，而非独立的疾病，很多耳部疾病、全身性疾病、精神心理因素等都可能引发耳鸣。
    - **脑梗**：即脑梗死，又称缺血性脑卒中，是指因脑部血液循环障碍，缺血、缺氧所致的局限性脑组织的缺血性坏死或软化，它是一种急性脑血管疾病，会对脑部组织造成实质性的损伤，严重时可危及生命并导致多种后遗症。
- **病因**：
    - **耳鸣**：常见病因包括外耳道耵聍栓塞、中耳炎、梅尼埃病、听神经瘤、噪声暴露、高血压、糖尿病、贫血、精神压力大、长期失眠等。
    - **脑梗**：主要病因是脑部血管堵塞，常见的危险因素有动脉粥样硬化（这是最常见的原因，血管壁上形成的斑块可导致血管狭窄甚至堵塞）、高血压（长期高血压可损伤血管内皮，促进动脉粥样硬化形成并增加血栓形成风险）、糖尿病（高血糖会损害血管和神经，影响脑部血液循环）、高血脂、吸烟、酗酒、肥胖、心脏病（如心房颤动，易形成心脏内血栓，血栓脱落可随血流进入脑部血管导致堵塞）等。
- **症状表现**：
    - **耳鸣**：主要症状就是耳内出现异常声音，如嗡嗡声、蝉鸣声、哨声、汽笛声等，可为单侧或双侧耳鸣，声音的响度和频率也因人而异，部分患者可能还会伴有听力下降、耳闷、眩晕等症状。
    - **脑梗**：症状较为复杂多样，取决于梗死的部位和面积大小。常见症状有突然出现的一侧肢体无力、麻木、口角歪斜、言语不清、吞咽困难、视物模糊、头晕、头痛、恶心呕吐、意识障碍等，严重的脑梗可能导致患者昏迷甚至死亡，即使经过治疗，也可能遗留不同程度的肢体残疾、认知障碍、言语障碍等后遗症。
- **治疗方法**：
    - **耳鸣**：治疗首先要明确病因，然后针对病因进行治疗。如耵聍栓塞需要取出耵聍；中耳炎需要进行抗感染治疗；梅尼埃病可使用改善内耳循环、减轻膜迷路积水的药物等；对于一些病因不明或病因治疗效果不佳的耳鸣，还可采用耳鸣习服疗法、认知行为疗法、掩蔽疗法等，同时可辅助使用营养神经、改善微循环的药物，如甲钴胺、银杏叶提取物等。
    - **脑梗**：治疗强调“时间就是大脑”，在发病超早期（一般指发病4.5小时内，部分患者可延长至6小时），符合适应证的患者可进行静脉溶栓治疗，使用药物溶解血栓，恢复脑部血流；对于大血管闭塞的患者，还可进行血管内介入治疗，如机械取栓等。在病情稳定后，需要进行康复治疗，包括肢体功能康复训练、言语康复训练、认知康复训练等，以促进患者功能恢复，提高生活质量。同时，还需要长期服用药物预防脑梗复发，如抗血小板聚集药物（阿司匹林、氯吡格雷等）、他汀类调脂药物（阿托伐他汀、瑞舒伐他汀等），以及控制血压、血糖、血脂等危险因素的药物。
如果出现耳鸣或怀疑有脑梗的相关症状，都应及时就医，进行详细的检查和诊断，以便采取针对性的治疗措施。另外，如果你有任何高血压相关的健康疑问，都可以随时告诉我，我会为你提供专业的建议和帮助。',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZB2DM7NWRYZF2HMNH9T','诊疗相关','疾病关联咨询','{"回答标签": ["解答详尽"], "场景标签": ["疾病关联咨询"], "患者标签": ["70岁", "高血压", "冠心病", "脑梗", "糖尿病", "曾有胸痛症状"], "补充标签": [], "患者发言标签": ["语气平和", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-12 15:11:47.702211+08','场景描述根据上下文患者的年龄、基础疾病、症状及本次咨询内容整合；患者提问对原发言进行了标点规范；回复案例仅保留原文未做改写，无敏感信息需要脱敏；回复规则无内容故留空。',0.9500,'bf2824ca87c024fc5508afc5b2f5a2fa','success',NULL,'20260211172011'),
	 ('01KH600GP44C5Y5X8N4X9J8J4K','53岁高脂血症患者，规律服用[阿托伐他汀]，存在肌肉酸痛症状，询问阿托伐他汀钙片与血滞通胶囊能否同时服用','我的甘油三酯高，阿托伐他汀钙片和血滞通胶囊这两种药可以同时吃吗？','阿托伐他汀钙片是常用的降脂药物，主要用于降低血液中的胆固醇和甘油三酯水平，稳定动脉粥样硬化斑块，减少心血管疾病风险。
血滞通胶囊属于中成药，常用于高脂血症的辅助治疗。这里有血滞通胶囊的药品说明书详细信息，你可以查看了解使用规范，不过一定要以医嘱为准。

[药品信息JSON]
content=

关于两种药物是否可以同时服用，需要医生根据你的具体健康状况、血脂水平、肝肾功能等进行综合评估后决定。建议你携带当前的用药方案和检查报告到[医院]就诊，由医生判断是否适合联合用药。
