INSERT INTO public.pipeline_data_items_rewritten (id,scenario_description,rewritten_question,rewritten_answer,rewritten_rule,source_dataset_id,source_item_id,scenario_type,sub_scenario_type,ai_tags,ai_score,ai_score_metadata,manual_score,manual_score_metadata,created_at,updated_at,rewrite_basis,scenario_confidence,trace_id,status,execution_metadata,batch_code) VALUES
	 ('01KH600GPAQ0JJ52341BGMW491','60岁糖尿病患者，无用药记录，本次告知昨天早中晚的血压分别为129/83mmHg、130/84mmHg、130/82mmHg，心率依次为70次/分、65次/分、64次/分，血压均达标，心率整体呈下降趋势，最低为64次/分，属于脉搏偏慢，患者表示最近心率低。','记录我昨天的血压：早晨129/83/70，中午130/84/65，晚上130/82/64，我最近心率低。','你能主动监测并告诉我，这个习惯非常棒！已经帮你保存了昨天的血压记录。
### 危险预警
你昨天的心率最低为64次/分，处于偏慢的状态，这可能会使身体供血不足，引发头晕、乏力等不适症状，需要引起重视，建议你尽快到医院进行检查，明确心率偏慢的原因。在就诊前，注意休息，避免剧烈运动和情绪激动，同时密切关注自己的身体状况，如是否出现头晕、黑矇、胸闷等症状。你可以查看医生的门诊排班信息，以便合理安排就诊时间：

scheduleStartDay=[日期], scheduleEndDay=[日期]
content=

### 血压点评
昨天你的血压在早晨为129/83mmHg，中午130/84mmHg，晚上130/82mmHg，心率分别为70、65、64次/分，这几次血压都符合家庭血压控制目标（低于135/85mmHg），属于正常范围，心率整体呈下降趋势。不过，单次的血压和心率记录存在一定局限性，建议你继续坚持监测血压和心率，记录更多的相关数据，包括测量时间、症状、活动量、情绪状态等，以便更全面地了解自己的血压和心率变化情况。
### 行动建议
1. **持续监测血压和心率**：建议你继续坚持每天监测血压和心率，最好在固定的时间、固定的体位下进行测量，如早晨起床后、晚上睡觉前等，每次测量2-3次，取平均值，并记录下来。同时，注意记录症状、活动量、情绪状态等信息，以便更好地分析血压和心率变化的原因。
2. **调整生活方式**：保持健康的生活方式对于控制血压和心率非常重要。建议你低盐饮食，每天的盐摄入量不超过5克；适量运动，如散步、慢跑、太极拳等，每周运动3-5次，每次30分钟左右；保持充足的睡眠，每天睡眠时间不少于7小时；避免情绪激动和精神紧张，保持心情舒畅。
3. **遵医嘱治疗**：如果你正在服用降压药或其他药物，一定要严格按照医生的嘱咐服用，不要自行增减药量或停药。同时，定期到医院复诊，让医生根据你的血压和心率情况调整治疗方案。
此外，了解更多关于高血压和心率管理的科普知识，有助于你更好地控制健康状况：

[科普文章列表JSON]',NULL,'01KGKSXY844Y5EY17412VB0SBW','01KGPDPZC61EQB41X7QV8EEJ22','记录血压','记录血压及心率情况','{"回答标签": ["预警提示", "带行动建议", "有推荐文章"], "场景标签": ["血压记录", "心率异常"], "患者标签": ["60岁", "糖尿病", "血压达标", "脉搏偏慢"], "补充标签": [], "患者发言标签": ["陈述事实", "咨询本人"]}',NULL,NULL,NULL,NULL,'2026-02-11 17:20:11.129268+08','2026-02-12 15:12:47.769636+08','场景描述结合患者年龄、病史、本次提供的血压心率数据及血压心率判定规则生成；患者提问根据本次发言改写为清晰的记录诉求；回复案例对具体日期、文章列表进行脱敏处理；场景根据患者发言的核心动作判定。',0.9500,'c35fef765d2efb3b0dda9f7f75c3134b','success',NULL,'20260211172011'),
	 ('01KH600GP0Y5BEXX2EBK23WX29','65岁的患者患有高血压、糖尿病、高脂血症，存在夜尿增多的症状，血压趋势上升，无服药数据，曾被引导回院复诊，现询问将复检时间定在[日期]是否可行。','我定在[日期]复检时间可以吗？','作为医生的数字分身，我主要专注于高血压慢病健康管理及科学指导，关于复检时间是否合适的问题，你可以查看医生的门诊排班信息，了解医生出诊时间，以便合理安排你的复检时间。

